import { GoogleGenAI, Type } from "@google/genai";
import { Coaster, CoasterType } from '../types';

let genAI: GoogleGenAI | null = null;

if (process.env.API_KEY) {
  genAI = new GoogleGenAI({ apiKey: process.env.API_KEY });
}

export const generateCoasterInfo = async (searchTerm: string): Promise<Partial<Coaster> | null> => {
  if (!genAI) {
    console.warn("Gemini API Key missing");
    return null;
  }

  try {
    const response = await genAI.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: `Find detailed specifications for the roller coaster "${searchTerm}". 
      Include height (in feet), speed (in mph), and track length (in feet) if known. 
      Return null if not found or not a real coaster.`,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            found: { type: Type.BOOLEAN },
            name: { type: Type.STRING },
            park: { type: Type.STRING },
            country: { type: Type.STRING },
            manufacturer: { type: Type.STRING },
            type: { 
              type: Type.STRING, 
              enum: ['Steel', 'Wooden', 'Hybrid', 'Alpine', 'Family', 'Powered', 'Bobsled'] 
            },
            specs: {
              type: Type.OBJECT,
              properties: {
                height: { type: Type.STRING, description: "Height in feet" },
                speed: { type: Type.STRING, description: "Speed in mph" },
                length: { type: Type.STRING, description: "Length in feet" },
                inversions: { type: Type.INTEGER }
              }
            }
          },
          required: ['found']
        }
      }
    });

    const text = response.text;
    if (!text) return null;

    const data = JSON.parse(text);
    if (!data.found) return null;

    let mappedType = CoasterType.Steel;
    const typeStr = data.type as string;
    if (Object.values(CoasterType).includes(typeStr as CoasterType)) {
      mappedType = typeStr as CoasterType;
    }

    return {
      name: data.name,
      park: data.park,
      country: data.country,
      manufacturer: data.manufacturer,
      type: mappedType,
      specs: data.specs,
      isCustom: true,
      imageUrl: 'https://picsum.photos/800/600?random=' + Math.floor(Math.random() * 1000)
    };

  } catch (error) {
    console.error("Gemini API Error:", error);
    return null;
  }
};

export const generateAppIcon = async (prompt: string): Promise<string | null> => {
  if (!genAI) return null;
  try {
    const response = await genAI.models.generateContent({
      model: 'gemini-2.5-flash-image',
      contents: {
        parts: [{ text: prompt + " Funny vector sticker app icon, white background, high contrast." }],
      },
    });
    if (response.candidates?.[0]?.content?.parts) {
      for (const part of response.candidates[0].content.parts) {
        if (part.inlineData) return `data:${part.inlineData.mimeType};base64,${part.inlineData.data}`;
      }
    }
    return null;
  } catch (error) {
    return null;
  }
};

import React, { createContext, useContext, useState, useEffect, ReactNode } from 'react';
import { User, Coaster, Credit, ViewState, WishlistEntry, RankingList } from '../types';
import { INITIAL_COASTERS, INITIAL_USERS, normalizeManufacturer, cleanName } from '../constants';
import { generateCoasterInfo, generateAppIcon } from '../services/geminiService';
import { fetchCoasterImageFromWiki } from '../services/wikipediaService';

export interface Notification {
  id: string;
  message: string;
  type: 'success' | 'error' | 'info';
}

interface AppContextType {
  activeUser: User;
  users: User[];
  coasters: Coaster[];
  credits: Credit[];
  wishlist: WishlistEntry[];
  currentView: ViewState;
  coasterListViewMode: 'CREDITS' | 'WISHLIST';
  notification: Notification | null;
  lastSearchQuery: string;

  // Actions
  switchUser: (userId: string) => void;
  addUser: (name: string, photo?: File) => void;
  updateUser: (userId: string, newName: string, photo?: File) => void;
  addCredit: (coasterId: string, date: string, notes: string, restraints: string, photo?: File) => void;
  updateCredit: (creditId: string, date: string, notes: string, restraints: string, photo?: File) => void;
  addNewCoaster: (coaster: Omit<Coaster, 'id'>) => Promise<Coaster>;
  searchOnlineCoaster: (query: string) => Promise<Partial<Coaster> | null>;
  generateIcon: (prompt: string) => Promise<string | null>;
  changeView: (view: ViewState) => void;
  setCoasterListViewMode: (mode: 'CREDITS' | 'WISHLIST') => void;
  deleteCredit: (creditId: string) => void;
  setLastSearchQuery: (query: string) => void;
  addToWishlist: (coasterId: string) => void;
  removeFromWishlist: (coasterId: string) => void;
  isInWishlist: (coasterId: string) => boolean;
  showNotification: (message: string, type?: 'success' | 'error' | 'info') => void;
  hideNotification: () => void;
  enrichDatabaseImages: () => Promise<void>;
  updateCoasterImage: (coasterId: string, imageUrl: string) => void;
  autoFetchCoasterImage: (coasterId: string) => Promise<string | null>;
  importData: (jsonData: any) => void;
  standardizeDatabase: () => void;

  // Ranking Actions
  updateRankings: (rankings: RankingList) => void;
}

const AppContext = createContext<AppContextType | undefined>(undefined);

const generateId = (prefix: string) => {
  const timestamp = Date.now().toString(36);
  const randomPart = Math.random().toString(36).substr(2, 9);
  return `${prefix}_${timestamp}_${randomPart}`;
};

export const AppProvider: React.FC<{ children: ReactNode }> = ({ children }) => {
  const [users, setUsers] = useState<User[]>(() => {
    const stored = localStorage.getItem('cc_users');
    return stored ? JSON.parse(stored) : INITIAL_USERS;
  });

  const [activeUser, setActiveUser] = useState<User>(() => {
    const storedId = localStorage.getItem('cc_active_user_id');
    const storedUsers = localStorage.getItem('cc_users');
    const parsedUsers = storedUsers ? JSON.parse(storedUsers) : INITIAL_USERS;
    return parsedUsers.find((u: User) => u.id === storedId) || parsedUsers[0];
  });

  const [coasters, setCoasters] = useState<Coaster[]>(() => {
    const stored = localStorage.getItem('cc_coasters');
    return stored ? JSON.parse(stored) : INITIAL_COASTERS;
  });

  const [credits, setCredits] = useState<Credit[]>(() => {
    const stored = localStorage.getItem('cc_credits');
    return stored ? JSON.parse(stored) : [];
  });

  const [wishlist, setWishlist] = useState<WishlistEntry[]>(() => {
    const stored = localStorage.getItem('cc_wishlist');
    return stored ? JSON.parse(stored) : [];
  });

  const [currentView, setCurrentView] = useState<ViewState>('DASHBOARD');
  const [coasterListViewMode, setCoasterListViewMode] = useState<'CREDITS' | 'WISHLIST'>('CREDITS');
  const [notification, setNotification] = useState<Notification | null>(null);
  const [lastSearchQuery, setLastSearchQuery] = useState('');

  useEffect(() => localStorage.setItem('cc_users', JSON.stringify(users)), [users]);
  useEffect(() => localStorage.setItem('cc_coasters', JSON.stringify(coasters)), [coasters]);
  useEffect(() => localStorage.setItem('cc_credits', JSON.stringify(credits)), [credits]);
  useEffect(() => localStorage.setItem('cc_wishlist', JSON.stringify(wishlist)), [wishlist]);
  useEffect(() => localStorage.setItem('cc_active_user_id', activeUser.id), [activeUser]);

  const showNotification = (message: string, type: 'success' | 'error' | 'info' = 'info') => {
    setNotification({ id: generateId('notif'), message, type });
    setTimeout(() => {
        setNotification(prev => (prev && prev.message === message ? null : prev));
    }, 4000);
  };

  const hideNotification = () => setNotification(null);

  const switchUser = (userId: string) => {
    const user = users.find(u => u.id === userId);
    if (user) {
        setActiveUser(user);
        showNotification(`Welcome back, ${user.name}!`);
    }
  };

  const addUser = (name: string, photo?: File) => {
    const processUser = (avatarUrl?: string) => {
        const newUser: User = {
          id: generateId('u'),
          name,
          avatarColor: ['bg-red-500', 'bg-green-500', 'bg-yellow-500', 'bg-purple-500', 'bg-pink-500', 'bg-indigo-500'][Math.floor(Math.random() * 6)],
          avatarUrl,
          rankings: { steel: [], wooden: [] }
        };
        setUsers([...users, newUser]);
        setActiveUser(newUser);
        showNotification(`Profile "${name}" created!`, 'success');
    };

    if (photo) {
        const reader = new FileReader();
        reader.onloadend = () => processUser(reader.result as string);
        reader.readAsDataURL(photo);
    } else {
        processUser();
    }
  };

  const updateUser = (userId: string, newName: string, photo?: File) => {
    const processUpdate = (avatarUrl?: string) => {
        setUsers(prevUsers => prevUsers.map(u => 
          u.id === userId ? { ...u, name: newName, ...(avatarUrl ? { avatarUrl } : {}) } : u
        ));
        if (activeUser.id === userId) {
          setActiveUser(prev => ({ ...prev, name: newName, ...(avatarUrl ? { avatarUrl } : {}) }));
        }
        showNotification("Profile updated", 'success');
    };

    if (photo) {
        const reader = new FileReader();
        reader.onloadend = () => processUpdate(reader.result as string);
        reader.readAsDataURL(photo);
    } else {
        processUpdate();
    }
  };

  const updateRankings = (rankings: RankingList) => {
    setUsers(prev => prev.map(u => u.id === activeUser.id ? { ...u, rankings } : u));
    setActiveUser(prev => ({ ...prev, rankings }));
    showNotification("Rankings updated!", 'success');
  };

  const addToWishlist = (coasterId: string) => {
    if (isInWishlist(coasterId)) {
        showNotification("Already in bucket list", 'info');
        return;
    }
    const entry: WishlistEntry = {
      id: generateId('w'),
      userId: activeUser.id,
      coasterId,
      addedAt: new Date().toISOString()
    };
    setWishlist([...wishlist, entry]);
    showNotification("Added to Bucket List", 'success');
  };

  const removeFromWishlist = (coasterId: string) => {
    setWishlist(prev => prev.filter(w => !(w.userId === activeUser.id && w.coasterId === coasterId)));
    showNotification("Removed from Bucket List", 'info');
  };

  const isInWishlist = (coasterId: string) => {
    return wishlist.some(w => w.userId === activeUser.id && w.coasterId === coasterId);
  };

  const addCredit = (coasterId: string, date: string, notes: string, restraints: string, photo?: File) => {
    if (isInWishlist(coasterId)) {
      setWishlist(prev => prev.filter(w => !(w.userId === activeUser.id && w.coasterId === coasterId)));
    }

    if (photo) {
        const reader = new FileReader();
        reader.onloadend = () => {
            const base64 = reader.result as string;
            saveCredit(coasterId, date, notes, restraints, base64);
        };
        reader.readAsDataURL(photo);
    } else {
        saveCredit(coasterId, date, notes, restraints);
    }
  };

  const saveCredit = (coasterId: string, date: string, notes: string, restraints: string, photoUrl?: string) => {
      const newCredit: Credit = {
      id: generateId('cr'),
      userId: activeUser.id,
      coasterId,
      date,
      rideCount: 1, 
      notes,
      restraints,
      photoUrl
    };
    setCredits([...credits, newCredit]);
    showNotification("Ride Logged Successfully!", 'success');
  };

  const updateCredit = (creditId: string, date: string, notes: string, restraints: string, photo?: File) => {
    const processUpdate = (photoUrl?: string) => {
      setCredits(prev => prev.map(c => {
        if (c.id === creditId) {
          return {
            ...c,
            date,
            notes,
            restraints,
            ...(photoUrl !== undefined ? { photoUrl } : {})
          };
        }
        return c;
      }));
      showNotification("Entry updated successfully", 'success');
    };

    if (photo) {
      const reader = new FileReader();
      reader.onloadend = () => {
        processUpdate(reader.result as string);
      };
      reader.readAsDataURL(photo);
    } else {
      processUpdate(); 
    }
  };

  const addNewCoaster = async (coasterData: Omit<Coaster, 'id'>): Promise<Coaster> => {
    const newId = generateId('c');
    let finalImageUrl = coasterData.imageUrl;
    if (!finalImageUrl || finalImageUrl.includes('picsum')) {
       const wikiImage = await fetchCoasterImageFromWiki(coasterData.name, coasterData.park);
       if (wikiImage) finalImageUrl = wikiImage;
    }

    const newCoaster: Coaster = { 
        ...coasterData, 
        park: cleanName(coasterData.park),
        country: cleanName(coasterData.country),
        manufacturer: normalizeManufacturer(coasterData.manufacturer),
        id: newId, 
        imageUrl: finalImageUrl 
    };
    setCoasters([...coasters, newCoaster]);
    showNotification("Added to Database", 'success');
    return newCoaster;
  };

  const searchOnlineCoaster = async (query: string) => {
    return await generateCoasterInfo(query);
  };

  const generateIcon = async (prompt: string) => {
    return await generateAppIcon(prompt);
  };

  const deleteCredit = (creditId: string) => {
    setCredits(prev => prev.filter(c => c.id !== creditId));
    showNotification("Credit deleted", 'info');
  }

  const changeView = (view: ViewState) => setCurrentView(view);

  const updateCoasterImage = (coasterId: string, imageUrl: string) => {
     setCoasters(prev => prev.map(c => c.id === coasterId ? { ...c, imageUrl } : c));
  };

  const autoFetchCoasterImage = async (coasterId: string): Promise<string | null> => {
      const coaster = coasters.find(c => c.id === coasterId);
      if (!coaster) return null;
      const imageUrl = await fetchCoasterImageFromWiki(coaster.name, coaster.park);
      if (imageUrl) {
          updateCoasterImage(coasterId, imageUrl);
          return imageUrl;
      }
      return null;
  };

  const enrichDatabaseImages = async () => {
      showNotification("Searching Wikipedia for photos...", 'info');
      const targets = coasters.filter(c => !c.imageUrl || c.imageUrl.includes('picsum'));
      let updatedCount = 0;
      const BATCH_SIZE = 5;
      for (let i = 0; i < targets.length; i += BATCH_SIZE) {
          const batch = targets.slice(i, i + BATCH_SIZE);
          const results = await Promise.all(
              batch.map(async (coaster) => {
                  const url = await fetchCoasterImageFromWiki(coaster.name, coaster.park);
                  return { id: coaster.id, url };
              })
          );
          setCoasters(prev => {
              let nextState = [...prev];
              results.forEach(res => {
                  if (res.url) {
                      const idx = nextState.findIndex(c => c.id === res.id);
                      if (idx !== -1) {
                          nextState[idx] = { ...nextState[idx], imageUrl: res.url };
                          updatedCount++;
                      }
                  }
              });
              return nextState;
          });
          await new Promise(r => setTimeout(r, 100));
      }
      if (updatedCount > 0) {
          showNotification(`Updated ${updatedCount} coasters with real photos!`, 'success');
      } else {
          showNotification(targets.length === 0 ? "Database already up to date." : "No new photos found.", 'info');
      }
  };

  const importData = (jsonData: any) => {
      try {
          const idTranslationTable: Record<string, string> = {}; 
          let mergedCoasterCount = 0;
          let addedCoasterCount = 0;
          let addedCreditCount = 0;

          if (jsonData.coasters && Array.isArray(jsonData.coasters)) {
              setCoasters(prev => {
                  const nextCoasters = [...prev];
                  jsonData.coasters.forEach((newC: Coaster) => {
                      const normName = cleanName(newC.name).toLowerCase();
                      const normPark = cleanName(newC.park).toLowerCase();
                      const existing = nextCoasters.find(c => 
                        c.id === newC.id || (cleanName(c.name).toLowerCase() === normName && cleanName(c.park).toLowerCase() === normPark)
                      );
                      if (existing) {
                        idTranslationTable[newC.id] = existing.id;
                        mergedCoasterCount++;
                      } else {
                        const newId = generateId('c');
                        idTranslationTable[newC.id] = newId;
                        nextCoasters.push({ ...newC, id: newId });
                        addedCoasterCount++;
                      }
                  });
                  return nextCoasters;
              });
          }

          if (jsonData.credits && Array.isArray(jsonData.credits)) {
              setCredits(prev => {
                  const existingIds = new Set(prev.map(c => c.id));
                  const toAdd = jsonData.credits
                    .filter((c: Credit) => !existingIds.has(c.id))
                    .map((c: Credit) => ({ ...c, userId: activeUser.id, coasterId: idTranslationTable[c.coasterId] || c.coasterId }));
                  addedCreditCount = toAdd.length;
                  return [...prev, ...toAdd];
              });
          }
          showNotification(`Import success! Added ${addedCreditCount} rides.`, 'success');
      } catch (e) {
          showNotification("Failed to import.", 'error');
      }
  };

  const standardizeDatabase = () => {
    const normalizedCoasters = coasters.map(c => ({
        ...c,
        name: cleanName(c.name),
        park: cleanName(c.park),
        manufacturer: normalizeManufacturer(c.manufacturer)
    }));
    const uniqueMap = new Map<string, string>();
    const idTranslationTable: Record<string, string> = {};
    const deduplicatedCoasters: Coaster[] = [];
    let mergedCount = 0;

    normalizedCoasters.forEach(c => {
        const key = `${c.name.toLowerCase()}|${c.park.toLowerCase()}`;
        if (uniqueMap.has(key)) {
            idTranslationTable[c.id] = uniqueMap.get(key)!;
            mergedCount++;
        } else {
            uniqueMap.set(key, c.id);
            deduplicatedCoasters.push(c);
        }
    });

    if (mergedCount > 0) {
        setCredits(prev => prev.map(cr => idTranslationTable[cr.coasterId] ? { ...cr, coasterId: idTranslationTable[cr.coasterId] } : cr));
        setCoasters(deduplicatedCoasters);
        showNotification(`Merged ${mergedCount} duplicates.`, 'success');
    }
  };

  return (
    <AppContext.Provider value={{
      activeUser, users, coasters, credits, wishlist, currentView, coasterListViewMode, notification, lastSearchQuery,
      switchUser, addUser, updateUser, addCredit, updateCredit, addNewCoaster, searchOnlineCoaster, generateIcon,
      changeView, setCoasterListViewMode, deleteCredit, addToWishlist, removeFromWishlist, isInWishlist,
      showNotification, hideNotification, setLastSearchQuery, enrichDatabaseImages, updateCoasterImage, autoFetchCoasterImage,
      importData, standardizeDatabase, updateRankings
    }}>
      {children}
    </AppContext.Provider>
  );
};

export const useAppContext = () => {
  const context = useContext(AppContext);
  if (!context) throw new Error("useAppContext must be used within AppProvider");
  return context;
};

import React, { useMemo, useState, useEffect } from 'react';
import { useAppContext } from '../context/AppContext';
import { PieChart, Pie, Cell, ResponsiveContainer, Tooltip } from 'recharts';
import { Trophy, ClipboardList, Palmtree, Layers, Factory, Flag, CalendarRange, Edit2, Globe, Hash, MapPin, Navigation } from 'lucide-react';
import EditCreditModal from './EditCreditModal';
import { Credit, Coaster } from '../types';
import { normalizeManufacturer } from '../constants';
import clsx from 'clsx';

type ChartMetric = 'PARK' | 'TYPE' | 'MANUFACTURER' | 'COUNTRY' | 'YEAR';

const Dashboard: React.FC = () => {
  const { credits, wishlist, coasters, activeUser, changeView, setCoasterListViewMode, setLastSearchQuery } = useAppContext();

  const [editingCreditData, setEditingCreditData] = useState<{ credit: Credit, coaster: Coaster } | null>(null);
  const [chartMetric, setChartMetric] = useState<ChartMetric>('PARK');
  const [nearbyParks, setNearbyParks] = useState<string[]>([]);

  // Geolocation Logic
  useEffect(() => {
    if ("geolocation" in navigator) {
      navigator.geolocation.getCurrentPosition(
        (position) => {
          // In a real production app, we'd use lat/lng to calculate distance.
          // For this prototype, we'll simulate the "Nearby" by highlighting top visited parks 
          // or a random subset of the database to show UI variety.
          const uniqueParks = Array.from(new Set(coasters.map(c => c.park)));
          setNearbyParks(uniqueParks.slice(0, 3));
        },
        (error) => console.warn("Location permission denied"),
        { timeout: 10000 }
      );
    }
  }, [coasters]);

  const userCredits = useMemo(() => 
    credits
      .filter(c => c.userId === activeUser.id)
      .sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime()),
  [credits, activeUser.id]);

  const userWishlist = useMemo(() => wishlist.filter(w => w.userId === activeUser.id), [wishlist, activeUser.id]);
  const uniqueCreditsCount = useMemo(() => new Set(userCredits.map(c => c.coasterId)).size, [userCredits]);
  const totalRidesCount = userCredits.length;

  const chartData = useMemo(() => {
    const dist: Record<string, number> = {};
    const processedCoasters = new Set<string>();
    userCredits.forEach(credit => {
      if (processedCoasters.has(credit.coasterId)) return;
      processedCoasters.add(credit.coasterId);
      const coaster = coasters.find(c => c.id === credit.coasterId);
      if (coaster) {
        let key = 'Unknown';
        switch (chartMetric) {
            case 'PARK': key = coaster.park; break;
            case 'TYPE': key = coaster.type; break;
            case 'MANUFACTURER': key = normalizeManufacturer(coaster.manufacturer); break;
            case 'COUNTRY': key = coaster.country; break;
            case 'YEAR': key = new Date(credit.date).getFullYear().toString(); break;
        }
        dist[key] = (dist[key] || 0) + 1;
      }
    });
    return Object.entries(dist).map(([name, value]) => ({ name, value })).sort((a, b) => b.value - a.value).slice(0, 8);
  }, [userCredits, coasters, chartMetric]);

  const COLORS = ['#0ea5e9', '#8b5cf6', '#f43f5e', '#10b981', '#f59e0b', '#6366f1', '#ec4899', '#14b8a6'];
  const recentCredit = userCredits.length > 0 ? userCredits[0] : null;
  const recentCoaster = recentCredit ? coasters.find(c => c.id === recentCredit.coasterId) : null;

  const handleLastRiddenClick = (e: React.MouseEvent) => {
    e.stopPropagation();
    if (recentCredit && recentCoaster) setEditingCreditData({ credit: recentCredit, coaster: recentCoaster });
  };

  const MetricButton = ({ mode, label, icon: Icon }: { mode: ChartMetric, label: string, icon: React.ElementType }) => (
      <button
        onClick={() => setChartMetric(mode)}
        className={clsx(
            "flex items-center gap-1.5 px-3 py-1.5 rounded-lg text-[10px] font-bold uppercase tracking-wide transition-all border",
            chartMetric === mode ? "bg-primary text-white border-primary shadow-lg shadow-primary/20" : "bg-slate-900 border-slate-700 text-slate-400 hover:text-white"
        )}
      >
          <Icon size={12} />
          {label}
      </button>
  );

  return (
    <div className="space-y-6 animate-fade-in pb-10">

      {/* Top Stats Row */}
      <div className="grid grid-cols-2 gap-4">
        <div 
            className="bg-slate-800 rounded-2xl p-5 shadow-lg border border-slate-700 relative overflow-hidden cursor-pointer active:scale-95 transition-transform group"
            onClick={() => { setCoasterListViewMode('CREDITS'); changeView('COASTER_LIST'); }}
        >
            <div className="absolute top-0 right-0 p-4 opacity-10 group-hover:opacity-20 transition-opacity"><Trophy size={80} /></div>
            <div className="relative z-10">
                <h2 className="text-slate-400 text-xs font-bold uppercase tracking-wider">Total Credits</h2>
                <div className="text-4xl font-bold text-white mt-1 tracking-tighter">{uniqueCreditsCount}</div>
                <div className="flex items-center gap-1 mt-2 text-xs font-medium text-slate-500 bg-slate-900/50 w-fit px-2 py-1 rounded-md">
                    <Hash size={10} /> {totalRidesCount} Total Rides
                </div>
            </div>
        </div>

        <div 
            className="bg-slate-800 rounded-2xl p-5 shadow-lg border border-slate-700 relative overflow-hidden cursor-pointer active:scale-95 transition-transform group" 
            onClick={() => { setCoasterListViewMode('WISHLIST'); changeView('COASTER_LIST'); }}
        >
            <div className="absolute top-0 right-0 p-4 opacity-10 group-hover:opacity-20 transition-opacity"><ClipboardList size={80} className="text-amber-500" /></div>
            <div className="relative z-10">
                 <h2 className="text-slate-400 text-xs font-bold uppercase tracking-wider">Bucket List</h2>
                 <div className="text-4xl font-bold text-white mt-1 tracking-tighter">{userWishlist.length}</div>
                 <p className="text-amber-500 mt-1 text-xs font-bold flex items-center gap-1">View List <ClipboardList size={10} /></p>
            </div>
        </div>
      </div>

      {/* Nearby Parks Widget */}
      {nearbyParks.length > 0 && (
          <div className="bg-gradient-to-r from-emerald-600/20 to-teal-600/10 p-5 rounded-2xl border border-emerald-500/30 shadow-xl">
              <div className="flex items-center justify-between mb-4">
                  <div className="flex items-center gap-2">
                    <Navigation size={18} className="text-emerald-400" />
                    <h3 className="font-bold text-white">Parks Near You</h3>
                  </div>
                  <span className="text-[10px] font-bold text-emerald-400/80 bg-emerald-400/10 px-2 py-0.5 rounded-full uppercase">GPS Active</span>
              </div>
              <div className="flex gap-3 overflow-x-auto no-scrollbar pb-1">
                  {nearbyParks.map(park => (
                      <button 
                        key={park}
                        onClick={() => { setLastSearchQuery(park); changeView('ADD_CREDIT'); }}
                        className="bg-slate-900/60 hover:bg-slate-900 border border-slate-700/50 p-3 rounded-xl flex items-center gap-2 shrink-0 transition-colors"
                      >
                          <div className="bg-emerald-500/10 p-1.5 rounded-lg text-emerald-400"><Palmtree size={14}/></div>
                          <span className="text-xs font-bold text-slate-200">{park}</span>
                      </button>
                  ))}
              </div>
          </div>
      )}

      {/* Statistics Panel */}
      <div className="bg-slate-800 p-5 rounded-2xl border border-slate-700 shadow-xl">
            <div className="mb-4">
                <div className="flex justify-between items-start mb-3">
                    <h3 className="text-lg font-bold text-white flex items-center gap-2">Statistics</h3>
                    <button 
                        onClick={() => changeView('PARK_STATS')}
                        className="bg-slate-700 hover:bg-slate-600 text-white p-2 rounded-lg transition-colors border border-slate-600 flex items-center gap-2"
                    >
                        <Globe size={18} />
                        <span className="text-xs font-bold hidden sm:inline">Map</span>
                    </button>
                </div>
                <div className="flex flex-wrap gap-2">
                    <MetricButton mode="PARK" label="Park" icon={Palmtree} />
                    <MetricButton mode="TYPE" label="Type" icon={Layers} />
                    <MetricButton mode="MANUFACTURER" label="Manufacturer" icon={Factory} />
                    <MetricButton mode="COUNTRY" label="Country" icon={Flag} />
                    <MetricButton mode="YEAR" label="Year" icon={CalendarRange} />
                </div>
            </div>

            {uniqueCreditsCount > 0 ? (
                <>
                    <div className="h-56 w-full relative">
                        <ResponsiveContainer width="100%" height="100%">
                            <PieChart>
                                <Pie data={chartData} cx="50%" cy="50%" innerRadius={60} outerRadius={85} paddingAngle={4} dataKey="value" stroke="none">
                                    {chartData.map((entry, index) => <Cell key={`cell-${index}`} fill={COLORS[index % COLORS.length]} />)}
                                </Pie>
                                <Tooltip contentStyle={{ backgroundColor: '#0f172a', borderColor: '#334155', borderRadius: '12px', fontSize: '12px' }} itemStyle={{ color: '#fff', fontWeight: 'bold' }} />
                            </PieChart>
                        </ResponsiveContainer>
                        <div className="absolute inset-0 flex items-center justify-center pointer-events-none">
                            <div className="text-center">
                                <div className="text-2xl font-bold text-white">{chartData.length}</div>
                                <div className="text-[10px] text-slate-500 uppercase font-bold tracking-wider">Groups</div>
                            </div>
                        </div>
                    </div>
                    <div className="grid grid-cols-2 gap-2 mt-2">
                        {chartData.map((entry, index) => (
                            <div key={entry.name} className="flex items-center justify-between text-xs bg-slate-900/50 p-2 rounded-lg border border-slate-700/50">
                                <div className="flex items-center gap-2 truncate pr-2">
                                    <div className="w-2.5 h-2.5 rounded-full shrink-0" style={{ backgroundColor: COLORS[index % COLORS.length] }}></div>
                                    <span className="text-slate-300 truncate font-medium">{entry.name}</span>
                                </div>
                                <span className="font-bold text-white">{entry.value}</span>
                            </div>
                        ))}
                    </div>
                </>
            ) : (
                <div className="h-56 w-full flex flex-col items-center justify-center text-slate-500 border-2 border-dashed border-slate-700 rounded-xl bg-slate-800/50 mt-2">
                    <button onClick={() => changeView('ADD_CREDIT')} className="bg-primary hover:bg-primary-hover text-white px-5 py-2 rounded-lg font-bold text-xs transition-colors shadow-lg shadow-primary/20">Add First Credit</button>
                </div>
            )}
      </div>

      {recentCoaster && (
        <div onClick={handleLastRiddenClick} className="bg-slate-800 p-4 rounded-xl border border-slate-700 flex gap-4 items-center cursor-pointer hover:bg-slate-750 hover:border-slate-500 transition-colors group relative overflow-hidden">
            <div className="absolute right-0 bottom-0 opacity-5 transform translate-x-4 translate-y-4"><Trophy size={100} /></div>
            {recentCoaster.imageUrl ? (
                <div className="w-16 h-16 rounded-lg overflow-hidden shrink-0 shadow-md"><img src={recentCoaster.imageUrl} alt={recentCoaster.name} className="w-full h-full object-cover" /></div>
            ) : (
                <div className="w-16 h-16 rounded-lg bg-slate-700 flex items-center justify-center shrink-0"><Trophy size={24} className="text-slate-500" /></div>
            )}
            <div className="relative z-10 min-0 flex-1">
                <div className="text-[10px] text-primary uppercase font-bold tracking-wide mb-0.5 flex items-center gap-1">Last Ridden <Edit2 size={8}/></div>
                <div className="font-bold text-lg text-white truncate">{recentCoaster.name}</div>
                <div className="text-xs text-slate-400 truncate">{recentCoaster.park}</div>
            </div>
        </div>
      )}

      {editingCreditData && <EditCreditModal credit={editingCreditData.credit} coaster={editingCreditData.coaster} onClose={() => setEditingCreditData(null)} />}
    </div>
  );
};

export default Dashboard;

import React, { useState, useMemo } from 'react';
import { useAppContext } from '../context/AppContext';
import { Trophy, ArrowLeft, Plus, Trash2, GripVertical, ChevronUp, ChevronDown, Save, Layers, TreeDeciduous } from 'lucide-react';
import clsx from 'clsx';
import { Coaster, CoasterType } from '../types';

const Rankings: React.FC = () => {
  const { activeUser, coasters, credits, updateRankings, changeView } = useAppContext();

  const [activeTab, setActiveTab] = useState<'steel' | 'wooden'>('steel');
  const [tempRankings, setTempRankings] = useState(activeUser.rankings || { steel: [], wooden: [] });

  // Filter only coasters that the user has actually RIDDEN
  const riddenCoasters = useMemo(() => {
      const riddenIds = new Set(credits.filter(c => c.userId === activeUser.id).map(c => c.coasterId));
      return coasters.filter(c => riddenIds.has(c.id));
  }, [coasters, credits, activeUser.id]);

  const availableCoasters = useMemo(() => {
      const currentList = activeTab === 'steel' ? tempRankings.steel : tempRankings.wooden;
      return riddenCoasters.filter(c => {
          const matchesType = activeTab === 'steel' 
            ? (c.type !== CoasterType.Wooden) 
            : (c.type === CoasterType.Wooden);
          return matchesType && !currentList.includes(c.id);
      });
  }, [riddenCoasters, tempRankings, activeTab]);

  const handleSave = () => {
      updateRankings(tempRankings);
      changeView('PROFILE');
  };

  const moveItem = (index: number, direction: 'up' | 'down') => {
      const list = [...(activeTab === 'steel' ? tempRankings.steel : tempRankings.wooden)];
      const target = direction === 'up' ? index - 1 : index + 1;
      if (target < 0 || target >= list.length) return;
      [list[index], list[target]] = [list[target], list[index]];
      setTempRankings({ ...tempRankings, [activeTab]: list });
  };

  const addItem = (id: string) => {
      const list = activeTab === 'steel' ? tempRankings.steel : tempRankings.wooden;
      if (list.length >= 10) return alert("Maximum 10 entries per list.");
      setTempRankings({ ...tempRankings, [activeTab]: [...list, id] });
  };

  const removeItem = (id: string) => {
      const list = activeTab === 'steel' ? tempRankings.steel : tempRankings.wooden;
      setTempRankings({ ...tempRankings, [activeTab]: list.filter(itemId => itemId !== id) });
  };

  const currentList = activeTab === 'steel' ? tempRankings.steel : tempRankings.wooden;

  return (
    <div className="animate-fade-in space-y-6 pb-20">
      <div className="flex items-center gap-3">
          <button onClick={() => changeView('PROFILE')} className="bg-slate-800 p-2 rounded-full border border-slate-700 text-slate-400 hover:text-white"><ArrowLeft size={20}/></button>
          <h2 className="text-2xl font-bold">My Rankings</h2>
      </div>

      <div className="flex bg-slate-800 p-1 rounded-xl border border-slate-700">
          <button onClick={() => setActiveTab('steel')} className={clsx("flex-1 py-3 rounded-lg flex items-center justify-center gap-2 transition-all font-bold", activeTab === 'steel' ? "bg-primary text-white" : "text-slate-400")}>
              <Layers size={18}/> Steel
          </button>
          <button onClick={() => setActiveTab('wooden')} className={clsx("flex-1 py-3 rounded-lg flex items-center justify-center gap-2 transition-all font-bold", activeTab === 'wooden' ? "bg-amber-600 text-white" : "text-slate-400")}>
              <TreeDeciduous size={18}/> Wooden
          </button>
      </div>

      <div className="space-y-3">
          {currentList.length === 0 ? (
              <div className="h-40 flex flex-col items-center justify-center bg-slate-800/50 border-2 border-dashed border-slate-700 rounded-2xl text-slate-500">
                  <Trophy size={32} className="mb-2 opacity-20"/>
                  <p className="text-sm">No {activeTab} coasters ranked yet.</p>
              </div>
          ) : (
              currentList.map((id, index) => {
                  const coaster = coasters.find(c => c.id === id);
                  if (!coaster) return null;
                  const rank = index + 1;
                  return (
                      <div key={id} className="bg-slate-800 border border-slate-700 p-3 rounded-xl flex items-center gap-4 group">
                          <div className={clsx(
                              "w-8 h-8 shrink-0 flex items-center justify-center rounded-lg font-bold text-sm",
                              rank === 1 ? "bg-yellow-500 text-slate-900" : rank === 2 ? "bg-slate-300 text-slate-900" : rank === 3 ? "bg-amber-700 text-white" : "bg-slate-900 text-slate-400"
                          )}>
                              {rank}
                          </div>
                          <div className="flex-1 min-w-0">
                              <div className="font-bold text-white truncate">{coaster.name}</div>
                              <div className="text-[10px] text-slate-400 truncate">{coaster.park}</div>
                          </div>
                          <div className="flex items-center gap-1">
                              <button onClick={() => moveItem(index, 'up')} className="p-1.5 hover:bg-slate-700 rounded-lg text-slate-500 hover:text-white"><ChevronUp size={16}/></button>
                              <button onClick={() => moveItem(index, 'down')} className="p-1.5 hover:bg-slate-700 rounded-lg text-slate-500 hover:text-white"><ChevronDown size={16}/></button>
                              <button onClick={() => removeItem(id)} className="p-1.5 hover:bg-red-500/10 rounded-lg text-slate-500 hover:text-red-400"><Trash2 size={16}/></button>
                          </div>
                      </div>
                  );
              })
          )}
      </div>

      {availableCoasters.length > 0 && currentList.length < 10 && (
          <div className="space-y-3 pt-4">
              <h3 className="text-xs font-bold text-slate-500 uppercase tracking-widest">Add Ridden Coasters</h3>
              <div className="flex flex-wrap gap-2">
                  {availableCoasters.slice(0, 8).map(coaster => (
                      <button 
                        key={coaster.id}
                        onClick={() => addItem(coaster.id)}
                        className="bg-slate-900 border border-slate-700 px-3 py-2 rounded-lg text-xs font-medium text-slate-300 hover:border-primary hover:text-white transition-all flex items-center gap-1.5"
                      >
                          <Plus size={12}/> {coaster.name}
                      </button>
                  ))}
              </div>
          </div>
      )}

      <div className="fixed bottom-20 left-4 right-4 z-50">
           <button 
            onClick={handleSave}
            className="w-full bg-emerald-600 hover:bg-emerald-500 text-white font-bold py-4 rounded-2xl shadow-xl flex items-center justify-center gap-2 transition-all transform active:scale-95"
           >
               <Save size={20}/> Save Rankings
           </button>
      </div>
    </div>
  );
};

