                        showAllLogs ? "bg-accent text-white border-accent shadow-lg shadow-accent/20" : "bg-slate-900 border-slate-700 text-slate-400"
                    )}
                  >
                    {showAllLogs ? <History size={12}/> : <ListFilter size={12}/>}
