                                            </div>

                                            <div className="flex items-center gap-2 text-[10px] text-slate-500">
                                                <span className="bg-slate-900/50 px-2 py-0.5 rounded text-slate-400 border border-slate-700/50">
                                                    <Tag size={10} className="mr-1" />
                                                    {item.coaster.type}
                                                </span>
                                                <span className="truncate opacity-75">{item.coaster.manufacturer}</span>
                                            </div>

                                            {item.type !== 'WISHLIST' && item.notes && (
                                                <p className="text-sm text-slate-300 italic line-clamp-1 border-l-2 border-slate-700 pl-2 mt-2">"{item.notes}"</p>
                                            )}
                                        </div>

                                        <div className="flex items-center justify-between mt-4 pt-3 border-t border-slate-700/50">
                                            <div className="flex items-center text-[10px] text-slate-500 font-medium">
                                                {item.type !== 'WISHLIST' ? (
                                                    <>
                                                        <Calendar size={10} className="mr-1.5 text-primary/70" />
                                                        {new Date((item as any).date).toLocaleDateString(undefined, { year: 'numeric', month: 'short', day: 'numeric' })}
                                                    </>
                                                ) : (
                                                    <span className="text-amber-500/70">Planned</span>
                                                )}
                                            </div>
                                            {item.type !== 'WISHLIST' && showAllLogs && (
                                                <span className="text-[10px] font-mono text-slate-600">ID: {item.id.slice(-4)}</span>
                                            )}
                                        </div>
                                    </div>
                                </div>
                            );
                        })}
                    </div>
                </div>
            )}
          </>
      )}

      {editingCreditData && (
          <EditCreditModal 
              credit={editingCreditData.credit}
              coaster={editingCreditData.coaster}
              onClose={() => setEditingCreditData(null)}
          />
      )}
    </div>
  );
};

export default CoasterList;

import React, { useState, useMemo } from 'react';
import { useAppContext } from '../context/AppContext';
import { Trophy, ArrowLeft, Plus, Trash2, ChevronUp, ChevronDown, Save, Layers, TreeDeciduous, Search, Hash } from 'lucide-react';
import clsx from 'clsx';
import { Coaster, CoasterType } from '../types';

const Rankings: React.FC = () => {
  const { activeUser, coasters, credits, updateRankings, changeView } = useAppContext();

  const [activeTab, setActiveTab] = useState<'steel' | 'wooden'>('steel');
  const [tempRankings, setTempRankings] = useState(activeUser.rankings || { steel: [], wooden: [] });
  const [searchQuery, setSearchQuery] = useState('');

  // Filter only coasters that the user has actually RIDDEN
  const riddenCoasters = useMemo(() => {
      const riddenIds = new Set(credits.filter(c => c.userId === activeUser.id).map(c => c.coasterId));
      return coasters.filter(c => riddenIds.has(c.id));
  }, [coasters, credits, activeUser.id]);

  // Statistics for the tabs
  const stats = useMemo(() => {
    const steelCount = riddenCoasters.filter(c => c.type !== CoasterType.Wooden).length;
    const woodenCount = riddenCoasters.filter(c => c.type === CoasterType.Wooden).length;
    return { steelCount, woodenCount };
  }, [riddenCoasters]);

  // Coasters available to be ADDED to the current list
  const availableCoasters = useMemo(() => {
      const currentList = activeTab === 'steel' ? tempRankings.steel : tempRankings.wooden;

      return riddenCoasters
        .filter(c => {
          const matchesType = activeTab === 'steel' 
            ? (c.type !== CoasterType.Wooden) 
            : (c.type === CoasterType.Wooden);

          const isNotRanked = !currentList.includes(c.id);
          const matchesSearch = c.name.toLowerCase().includes(searchQuery.toLowerCase()) || 
                               c.park.toLowerCase().includes(searchQuery.toLowerCase());

          return matchesType && isNotRanked && matchesSearch;
        })
        .sort((a, b) => a.name.localeCompare(b.name));
  }, [riddenCoasters, tempRankings, activeTab, searchQuery]);

  const handleSave = () => {
      updateRankings(tempRankings);
      changeView('PROFILE');
  };

  const moveItem = (index: number, direction: 'up' | 'down') => {
      const listKey = activeTab === 'steel' ? 'steel' : 'wooden';
      const list = [...tempRankings[listKey]];
      const target = direction === 'up' ? index - 1 : index + 1;
      if (target < 0 || target >= list.length) return;
      [list[index], list[target]] = [list[target], list[index]];
      setTempRankings({ ...tempRankings, [listKey]: list });
  };

  const addItem = (id: string) => {
      const listKey = activeTab === 'steel' ? 'steel' : 'wooden';
      const list = tempRankings[listKey];
      if (list.length >= 10) {
        alert("Maximum 10 entries per list. Remove a coaster to add a new one.");
        return;
      }
      setTempRankings({ ...tempRankings, [listKey]: [...list, id] });
      setSearchQuery(''); // Clear search after adding
  };

  const removeItem = (id: string) => {
      const listKey = activeTab === 'steel' ? 'steel' : 'wooden';
      setTempRankings({ ...tempRankings, [listKey]: tempRankings[listKey].filter(itemId => itemId !== id) });
  };

  const currentRankedList = activeTab === 'steel' ? tempRankings.steel : tempRankings.wooden;

  return (
    <div className="animate-fade-in space-y-6 pb-24">
      <div className="flex items-center gap-3">
          <button onClick={() => changeView('PROFILE')} className="bg-slate-800 p-2 rounded-full border border-slate-700 text-slate-400 hover:text-white transition-colors">
            <ArrowLeft size={20}/>
          </button>
          <h2 className="text-2xl font-bold">My Top 10 Rankings</h2>
      </div>

      {/* Tab Switcher */}
      <div className="flex bg-slate-900/50 p-1 rounded-2xl border border-slate-700">
          <button 
            onClick={() => { setActiveTab('steel'); setSearchQuery(''); }} 
            className={clsx(
                "flex-1 py-3 rounded-xl flex flex-col items-center justify-center gap-1 transition-all", 
                activeTab === 'steel' ? "bg-primary text-white shadow-lg shadow-primary/20" : "text-slate-500 hover:text-slate-300"
            )}
          >
              <div className="flex items-center gap-2 font-bold uppercase text-[10px] tracking-widest">
                <Layers size={14}/> Steel
              </div>
              <span className="text-[10px] opacity-70 font-medium">{stats.steelCount} Credits</span>
          </button>
          <button 
            onClick={() => { setActiveTab('wooden'); setSearchQuery(''); }} 
            className={clsx(
                "flex-1 py-3 rounded-xl flex flex-col items-center justify-center gap-1 transition-all", 
                activeTab === 'wooden' ? "bg-amber-600 text-white shadow-lg shadow-amber-600/20" : "text-slate-500 hover:text-slate-300"
            )}
          >
              <div className="flex items-center gap-2 font-bold uppercase text-[10px] tracking-widest">
                <TreeDeciduous size={14}/> Wooden
              </div>
              <span className="text-[10px] opacity-70 font-medium">{stats.woodenCount} Credits</span>
          </button>
      </div>

      {/* Current Rankings List */}
      <div className="space-y-3">
          <h3 className="text-[10px] font-bold text-slate-500 uppercase tracking-widest px-1">Your Top 10 {activeTab}</h3>
          {currentRankedList.length === 0 ? (
              <div className="h-32 flex flex-col items-center justify-center bg-slate-800/30 border-2 border-dashed border-slate-700 rounded-2xl text-slate-500">
                  <Trophy size={28} className="mb-2 opacity-20"/>
                  <p className="text-xs">Your ranking is empty.</p>
              </div>
          ) : (
              currentRankedList.map((id, index) => {
                  const coaster = coasters.find(c => c.id === id);
                  if (!coaster) return null;
                  const rank = index + 1;
                  return (
                      <div key={id} className="bg-slate-800 border border-slate-700 p-3 rounded-xl flex items-center gap-4 animate-scale-in">
                          <div className={clsx(
                              "w-8 h-8 shrink-0 flex items-center justify-center rounded-lg font-bold text-sm shadow-inner",
                              rank === 1 ? "bg-yellow-500 text-slate-900" : 
                              rank === 2 ? "bg-slate-300 text-slate-900" : 
                              rank === 3 ? "bg-amber-700 text-white" : 
                              "bg-slate-900 text-slate-400"
                          )}>
                              {rank}
                          </div>
                          <div className="flex-1 min-w-0">
                              <div className="font-bold text-white text-sm truncate">{coaster.name}</div>
                              <div className="text-[10px] text-slate-400 truncate">{coaster.park}</div>
                          </div>
                          <div className="flex items-center gap-1">
                              <div className="flex flex-col">
                                <button onClick={() => moveItem(index, 'up')} disabled={index === 0} className="p-1 text-slate-500 hover:text-white disabled:opacity-20"><ChevronUp size={14}/></button>
                                <button onClick={() => moveItem(index, 'down')} disabled={index === currentRankedList.length - 1} className="p-1 text-slate-500 hover:text-white disabled:opacity-20"><ChevronDown size={14}/></button>
                              </div>
                              <button onClick={() => removeItem(id)} className="p-2 ml-1 bg-red-500/10 text-slate-500 hover:text-red-400 hover:bg-red-500/20 rounded-lg transition-colors">
                                <Trash2 size={16}/>
                              </button>
                          </div>
                      </div>
                  );
              })
          )}
      </div>

      {/* Search & Add New Section */}
      {currentRankedList.length < 10 && (
          <div className="space-y-4 pt-4 border-t border-slate-800">
              <div className="flex items-center justify-between">
                  <h3 className="text-[10px] font-bold text-slate-500 uppercase tracking-widest px-1">Add Ridden Coasters</h3>
                  <div className="text-[10px] font-bold text-primary bg-primary/10 px-2 py-0.5 rounded-full">{availableCoasters.length} Available</div>
              </div>

              <div className="relative">
                  <Search size={16} className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-500" />
                  <input 
                    type="text" 
                    placeholder={`Search your ${activeTab} credits...`} 
                    value={searchQuery}
                    onChange={(e) => setSearchQuery(e.target.value)}
                    className="w-full bg-slate-900 border border-slate-700 rounded-xl pl-10 py-2.5 text-sm text-white focus:ring-1 focus:ring-primary focus:outline-none"
                  />
              </div>

              <div className="grid grid-cols-1 gap-2 max-h-60 overflow-y-auto pr-1 no-scrollbar">
                  {availableCoasters.map(coaster => (
                      <button 
                        key={coaster.id}
                        onClick={() => addItem(coaster.id)}
                        className="bg-slate-800/40 border border-slate-700/50 p-2.5 rounded-xl text-left hover:bg-slate-800 hover:border-slate-600 transition-all flex items-center justify-between group"
                      >
                          <div className="min-w-0 flex-1">
                              <div className="text-xs font-bold text-slate-200 truncate group-hover:text-white">{coaster.name}</div>
                              <div className="text-[10px] text-slate-500 truncate">{coaster.park}</div>
                          </div>
                          <div className="bg-primary/10 text-primary p-1.5 rounded-lg opacity-0 group-hover:opacity-100 transition-opacity">
                              <Plus size={14}/>
                          </div>
                      </button>
                  ))}
                  {availableCoasters.length === 0 && riddenCoasters.length > 0 && searchQuery && (
                      <p className="text-center text-xs text-slate-500 py-4 italic">No matches for "{searchQuery}"</p>
                  )}
                  {riddenCoasters.length === 0 && (
                      <div className="text-center py-6 bg-slate-900/30 rounded-2xl border border-dashed border-slate-800">
                        <p className="text-xs text-slate-500 mb-3 px-4">You haven't logged any {activeTab} coasters yet!</p>
                        <button onClick={() => changeView('ADD_CREDIT')} className="text-[10px] font-bold text-primary uppercase tracking-widest border border-primary/30 px-3 py-1.5 rounded-lg hover:bg-primary/10">Log Rides Now</button>
                      </div>
                  )}
              </div>
          </div>
      )}

      {/* Global Save Button */}
      <div className="fixed bottom-20 left-4 right-4 z-50">
           <button 
            onClick={handleSave}
            className="w-full bg-emerald-600 hover:bg-emerald-500 text-white font-bold py-4 rounded-2xl shadow-xl shadow-emerald-900/30 flex items-center justify-center gap-2 transition-all transform active:scale-95"
           >
               <Save size={20}/> Save All Rankings
           </button>
      </div>
    </div>
  );
};

export default Rankings;

import React, { useMemo, useState, useEffect } from 'react';
import { useAppContext } from '../context/AppContext';
import { PieChart, Pie, Cell, ResponsiveContainer, Tooltip } from 'recharts';
import { Trophy, ClipboardList, Palmtree, Layers, Factory, Flag, CalendarRange, Edit2, Globe, Hash, MapPin, Navigation, ChevronRight } from 'lucide-react';
import EditCreditModal from './EditCreditModal';
import { Credit, Coaster } from '../types';
import { normalizeManufacturer } from '../constants';
import clsx from 'clsx';

type ChartMetric = 'PARK' | 'TYPE' | 'MANUFACTURER' | 'COUNTRY' | 'YEAR';

const Dashboard: React.FC = () => {
  const { credits, wishlist, coasters, activeUser, changeView, setCoasterListViewMode, setLastSearchQuery } = useAppContext();

  const [editingCreditData, setEditingCreditData] = useState<{ credit: Credit, coaster: Coaster } | null>(null);
  const [chartMetric, setChartMetric] = useState<ChartMetric>('PARK');
  const [nearbyParks, setNearbyParks] = useState<string[]>([]);

  // Geolocation Logic
  useEffect(() => {
    if ("geolocation" in navigator) {
      navigator.geolocation.getCurrentPosition(
        (position) => {
          const uniqueParks = Array.from(new Set(coasters.map(c => c.park)));
          setNearbyParks(uniqueParks.slice(0, 3));
        },
        (error) => console.warn("Location permission denied"),
        { timeout: 10000 }
      );
    }
  }, [coasters]);

  const userCredits = useMemo(() => 
    credits
      .filter(c => c.userId === activeUser.id)
      .sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime()),
  [credits, activeUser.id]);

  const userWishlist = useMemo(() => wishlist.filter(w => w.userId === activeUser.id), [wishlist, activeUser.id]);
  const uniqueCreditsCount = useMemo(() => new Set(userCredits.map(c => c.coasterId)).size, [userCredits]);
  const totalRidesCount = userCredits.length;

  const chartData = useMemo(() => {
    const dist: Record<string, number> = {};
    const processedCoasters = new Set<string>();
    userCredits.forEach(credit => {
      if (processedCoasters.has(credit.coasterId)) return;
      processedCoasters.add(credit.coasterId);
      const coaster = coasters.find(c => c.id === credit.coasterId);
      if (coaster) {
        let key = 'Unknown';
        switch (chartMetric) {
            case 'PARK': key = coaster.park; break;
            case 'TYPE': key = coaster.type; break;
            case 'MANUFACTURER': key = normalizeManufacturer(coaster.manufacturer); break;
            case 'COUNTRY': key = coaster.country; break;
            case 'YEAR': key = new Date(credit.date).getFullYear().toString(); break;
        }
        dist[key] = (dist[key] || 0) + 1;
      }
    });
    return Object.entries(dist).map(([name, value]) => ({ name, value })).sort((a, b) => b.value - a.value).slice(0, 8);
  }, [userCredits, coasters, chartMetric]);

  const COLORS = ['#0ea5e9', '#8b5cf6', '#f43f5e', '#10b981', '#f59e0b', '#6366f1', '#ec4899', '#14b8a6'];
  const recentCredit = userCredits.length > 0 ? userCredits[0] : null;
  const recentCoaster = recentCredit ? coasters.find(c => c.id === recentCredit.coasterId) : null;

  const handleLastRiddenClick = (e: React.MouseEvent) => {
    e.stopPropagation();
    if (recentCredit && recentCoaster) setEditingCreditData({ credit: recentCredit, coaster: recentCoaster });
  };

  const MetricButton = ({ mode, label, icon: Icon }: { mode: ChartMetric, label: string, icon: React.ElementType }) => (
      <button
        onClick={() => setChartMetric(mode)}
        className={clsx(
            "flex items-center gap-1.5 px-3 py-1.5 rounded-lg text-[10px] font-bold uppercase tracking-wide transition-all border",
            chartMetric === mode ? "bg-primary text-white border-primary shadow-lg shadow-primary/20" : "bg-slate-900 border-slate-700 text-slate-400 hover:text-white"
        )}
      >
          <Icon size={12} />
          {label}
      </button>
  );

  return (
    <div className="space-y-6 animate-fade-in pb-10">

      {/* 1. Rankings Shortcut (New Top Placement) */}
      <button 
          onClick={() => changeView('RANKINGS')}
          className="w-full bg-gradient-to-br from-amber-500/20 via-yellow-600/10 to-transparent border border-amber-500/30 p-4 rounded-2xl flex items-center justify-between group active:scale-[0.98] transition-all shadow-xl shadow-amber-950/20"
      >
          <div className="flex items-center gap-4">
              <div className="bg-gradient-to-br from-amber-400 to-yellow-600 p-2.5 rounded-xl text-slate-900 shadow-lg shadow-amber-500/30">
                  <Trophy size={22} fill="currentColor" />
              </div>
              <div className="text-left">
                  <h3 className="font-bold text-white text-base leading-tight">My Top 10 Rankings</h3>
                  <p className="text-[10px] text-amber-500/80 font-bold uppercase tracking-widest mt-0.5">Manage Your Credits</p>
              </div>
          </div>
          <ChevronRight size={18} className="text-amber-500/50 group-hover:text-amber-500 group-hover:translate-x-1 transition-all" />
      </button>

      {/* 2. Top Stats Row */}
      <div className="grid grid-cols-2 gap-4">
        <div 
            className="bg-slate-800 rounded-2xl p-5 shadow-lg border border-slate-700 relative overflow-hidden cursor-pointer active:scale-95 transition-transform group"
            onClick={() => { setCoasterListViewMode('CREDITS'); changeView('COASTER_LIST'); }}
        >
            <div className="absolute top-0 right-0 p-4 opacity-10 group-hover:opacity-20 transition-opacity"><Trophy size={80} /></div>
            <div className="relative z-10">
                <h2 className="text-slate-400 text-xs font-bold uppercase tracking-wider">Total Credits</h2>
                <div className="text-4xl font-bold text-white mt-1 tracking-tighter">{uniqueCreditsCount}</div>
                <div className="flex items-center gap-1 mt-2 text-xs font-medium text-slate-500 bg-slate-900/50 w-fit px-2 py-1 rounded-md">
                    <Hash size={10} /> {totalRidesCount} Total Rides
                </div>
            </div>
        </div>

        <div 
            className="bg-slate-800 rounded-2xl p-5 shadow-lg border border-slate-700 relative overflow-hidden cursor-pointer active:scale-95 transition-transform group" 
            onClick={() => { setCoasterListViewMode('WISHLIST'); changeView('COASTER_LIST'); }}
        >
            <div className="absolute top-0 right-0 p-4 opacity-10 group-hover:opacity-20 transition-opacity"><ClipboardList size={80} className="text-amber-500" /></div>
            <div className="relative z-10">
                 <h2 className="text-slate-400 text-xs font-bold uppercase tracking-wider">Bucket List</h2>
                 <div className="text-4xl font-bold text-white mt-1 tracking-tighter">{userWishlist.length}</div>
                 <p className="text-amber-500 mt-1 text-xs font-bold flex items-center gap-1">View List <ClipboardList size={10} /></p>
            </div>
        </div>
      </div>

      {/* 3. Statistics Panel */}
      <div className="bg-slate-800 p-5 rounded-2xl border border-slate-700 shadow-xl">
            <div className="mb-4">
                <div className="flex justify-between items-start mb-3">
                    <h3 className="text-lg font-bold text-white flex items-center gap-2">Statistics</h3>
                    <button 
                        onClick={() => changeView('PARK_STATS')}
                        className="bg-slate-700 hover:bg-slate-600 text-white p-2 rounded-lg transition-colors border border-slate-600 flex items-center gap-2"
                    >
                        <Globe size={18} />
                        <span className="text-xs font-bold hidden sm:inline">Map</span>
                    </button>
                </div>
                <div className="flex flex-wrap gap-2">
                    <MetricButton mode="PARK" label="Park" icon={Palmtree} />
                    <MetricButton mode="TYPE" label="Type" icon={Layers} />
                    <MetricButton mode="MANUFACTURER" label="Manufacturer" icon={Factory} />
                    <MetricButton mode="COUNTRY" label="Country" icon={Flag} />
                    <MetricButton mode="YEAR" label="Year" icon={CalendarRange} />
                </div>
            </div>

            {uniqueCreditsCount > 0 ? (
                <>
                    <div className="h-56 w-full relative">
                        <ResponsiveContainer width="100%" height="100%">
                            <PieChart>
                                <Pie data={chartData} cx="50%" cy="50%" innerRadius={60} outerRadius={85} paddingAngle={4} dataKey="value" stroke="none">
                                    {chartData.map((entry, index) => <Cell key={`cell-${index}`} fill={COLORS[index % COLORS.length]} />)}
                                </Pie>
                                <Tooltip contentStyle={{ backgroundColor: '#0f172a', borderColor: '#334155', borderRadius: '12px', fontSize: '12px' }} itemStyle={{ color: '#fff', fontWeight: 'bold' }} />
                            </PieChart>
                        </ResponsiveContainer>
                        <div className="absolute inset-0 flex items-center justify-center pointer-events-none">
                            <div className="text-center">
                                <div className="text-2xl font-bold text-white">{chartData.length}</div>
                                <div className="text-[10px] text-slate-500 uppercase font-bold tracking-wider">Groups</div>
                            </div>
                        </div>
                    </div>
                    <div className="grid grid-cols-2 gap-2 mt-2">
                        {chartData.map((entry, index) => (
                            <div key={entry.name} className="flex items-center justify-between text-xs bg-slate-900/50 p-2 rounded-lg border border-slate-700/50">
                                <div className="flex items-center gap-2 truncate pr-2">
                                    <div className="w-2.5 h-2.5 rounded-full shrink-0" style={{ backgroundColor: COLORS[index % COLORS.length] }}></div>
                                    <span className="text-slate-300 truncate font-medium">{entry.name}</span>
                                </div>
                                <span className="font-bold text-white">{entry.value}</span>
                            </div>
                        ))}
                    </div>
                </>
            ) : (
                <div className="h-56 w-full flex flex-col items-center justify-center text-slate-500 border-2 border-dashed border-slate-700 rounded-xl bg-slate-800/50 mt-2">
                    <button onClick={() => changeView('ADD_CREDIT')} className="bg-primary hover:bg-primary-hover text-white px-5 py-2 rounded-lg font-bold text-xs transition-colors shadow-lg shadow-primary/20">Add First Credit</button>
                </div>
            )}
      </div>

      {recentCoaster && (
        <div onClick={handleLastRiddenClick} className="bg-slate-800 p-4 rounded-xl border border-slate-700 flex gap-4 items-center cursor-pointer hover:bg-slate-750 hover:border-slate-500 transition-colors group relative overflow-hidden">
            <div className="absolute right-0 bottom-0 opacity-5 transform translate-x-4 translate-y-4"><Trophy size={100} /></div>
            {recentCoaster.imageUrl ? (
                <div className="w-16 h-16 rounded-lg overflow-hidden shrink-0 shadow-md"><img src={recentCoaster.imageUrl} alt={recentCoaster.name} className="w-full h-full object-cover" /></div>
            ) : (
                <div className="w-16 h-16 rounded-lg bg-slate-700 flex items-center justify-center shrink-0"><Trophy size={24} className="text-slate-500" /></div>
            )}
            <div className="relative z-10 min-0 flex-1">
                <div className="text-[10px] text-primary uppercase font-bold tracking-wide mb-0.5 flex items-center gap-1">Last Ridden <Edit2 size={8}/></div>
                <div className="font-bold text-lg text-white truncate">{recentCoaster.name}</div>
                <div className="text-xs text-slate-400 truncate">{recentCoaster.park}</div>
            </div>
        </div>
      )}

      {/* 4. Nearby Parks Widget (Moved to bottom) */}
      {nearbyParks.length > 0 && (
          <div className="bg-gradient-to-r from-emerald-600/20 to-teal-600/10 p-5 rounded-2xl border border-emerald-500/30 shadow-xl">
              <div className="flex items-center justify-between mb-4">
                  <div className="flex items-center gap-2">
                    <Navigation size={18} className="text-emerald-400" />
                    <h3 className="font-bold text-white">Parks Near You</h3>
                  </div>
                  <span className="text-[10px] font-bold text-emerald-400/80 bg-emerald-400/10 px-2 py-0.5 rounded-full uppercase">GPS Active</span>
              </div>
              <div className="flex gap-3 overflow-x-auto no-scrollbar pb-1">
                  {nearbyParks.map(park => (
                      <button 
