    if (searchTerm) {
        const normalizedSearch = normalizeText(searchTerm);
        result = result.filter(c => normalizeText(c.name).includes(normalizedSearch) || normalizeText(c.park).includes(normalizedSearch));
    }
    if (filterType !== 'All') result = result.filter(c => c.type === filterType);
    if (hideRidden) result = result.filter(c => !credits.some(cr => cr.userId === activeUser.id && cr.coasterId === c.id));
    return result.sort((a, b) => a.name.localeCompare(b.name));
  }, [coasters, searchTerm, filterType, hideRidden, credits, activeUser.id]);

  const coasterRideHistory = useMemo(() => {
    if (!selectedCoaster) return [];
    return credits
      .filter(c => c.userId === activeUser.id && c.coasterId === selectedCoaster.id)
      .sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime());
  }, [selectedCoaster, credits, activeUser.id]);

  const handleMagicSearch = async () => {
      if (!searchTerm) return;
      setIsAiSearching(true);
      setAiDiscoveryResults([]);
      const results = await searchOnlineCoaster(searchTerm);
      setIsAiSearching(false);

      if (results && results.length > 0) {
          if (results.length === 1) {
              const res = results[0];
              if (window.confirm(`Found: ${res.name} at ${res.park}. Add to database?`)) {
                  const newC = await addNewCoaster(res as Omit<Coaster, 'id'>);
                  setSelectedCoaster(newC);
              }
          } else {
              setAiDiscoveryResults(results);
          }
      } else {
          showNotification("No coasters found. Try refining your search.", "info");
      }
  };

  const handleAddDiscovery = async (item: Partial<Coaster>) => {
      const newC = await addNewCoaster(item as Omit<Coaster, 'id'>);
      setAiDiscoveryResults(prev => prev.filter(p => p.name !== item.name));
      setSelectedCoaster(newC);
  };

  const handleAddAllDiscovery = async () => {
      for (const item of aiDiscoveryResults) {
          await addNewCoaster(item as Omit<Coaster, 'id'>);
      }
      setAiDiscoveryResults([]);
      showNotification(`Added ${aiDiscoveryResults.length} coasters to your database!`, 'success');
  };

  const handleManualSubmit = async (e: React.FormEvent) => {
      e.preventDefault();
      const newC = await addNewCoaster({ ...manualCoasterData, isCustom: true });
      setIsAddingManually(false);
      setSelectedCoaster(newC);
  };

  const processLog = (filterByPark: boolean) => {
    if (selectedCoaster) {
        addCredit(selectedCoaster.id, date, notes, restraints, photo);
        if (filterByPark) setSearchTerm(selectedCoaster.park);
        setNotes(''); setRestraints(''); setPhoto(undefined);
    }
  };

  const isSelectedWishlisted = selectedCoaster ? isInWishlist(selectedCoaster.id) : false;

  if (isAddingManually) {
      return (
          <div className="animate-fade-in pb-20">
              <div className="flex items-center gap-3 mb-6">
                <button onClick={() => setIsAddingManually(false)} className="p-2 rounded-xl bg-slate-800 border border-slate-700 text-slate-400"><BackIcon size={20}/></button>
                <h2 className="text-xl font-bold">Add Coaster Manually</h2>
              </div>
              <form onSubmit={handleManualSubmit} className="bg-slate-800 p-6 rounded-2xl border border-slate-700 space-y-4">
                  <input required placeholder="Coaster Name" value={manualCoasterData.name} onChange={e => setManualCoasterData({...manualCoasterData, name: e.target.value})} className="w-full bg-slate-900 border border-slate-600 rounded-xl p-3 text-white" />
                  <input required placeholder="Park Name" value={manualCoasterData.park} onChange={e => setManualCoasterData({...manualCoasterData, park: e.target.value})} className="w-full bg-slate-900 border border-slate-600 rounded-xl p-3 text-white" />
                  <div className="pt-4"><button type="submit" className="w-full bg-primary py-3.5 rounded-xl font-bold">Save & Log Ride</button></div>
              </form>
          </div>
      );
  }

  if (selectedCoaster) {
      return (
          <div className="animate-fade-in pb-24 space-y-4">
                <div className="sticky top-0 -mx-4 -mt-4 p-4 z-20 bg-slate-900/95 backdrop-blur-md border-b border-slate-700/50 flex gap-2">
                    <button onClick={() => setSelectedCoaster(null)} className="p-3 rounded-xl bg-slate-800 border border-slate-700 text-slate-400"><BackIcon size={20}/></button>
                    <button onClick={() => processLog(true)} className="flex-1 bg-emerald-500/10 text-emerald-400 font-bold py-3 rounded-xl border border-emerald-500/30 flex items-center justify-center gap-2">Log & View Park</button>
                </div>

                {selectedCoaster.imageUrl && (
                    <div className="w-full h-48 rounded-2xl overflow-hidden shadow-lg border border-slate-700 relative">
                        <img src={selectedCoaster.imageUrl} alt={selectedCoaster.name} className="w-full h-full object-cover" />
                        <div className="absolute inset-0 bg-gradient-to-t from-slate-950 via-transparent to-transparent" />
                        <div className="absolute bottom-4 left-4">
                            <h2 className="text-3xl font-black text-white leading-tight italic drop-shadow-md">{selectedCoaster.name}</h2>
                            <div className="text-slate-300 text-sm font-bold flex items-center gap-1 uppercase tracking-wider"><Globe size={14} className="text-primary"/> {selectedCoaster.park}</div>
                        </div>
                    </div>
                )}

                <div className="bg-slate-800 p-5 rounded-3xl border border-slate-700 space-y-4 shadow-xl">
                    <div className="flex items-center justify-between mb-2">
                        <h3 className="font-bold text-white flex items-center gap-2 text-sm uppercase tracking-widest text-slate-400"><Clock size={16} className="text-primary"/> Quick Log</h3>
                    </div>
                    <div>
                        <label className="block text-[10px] font-bold text-slate-500 uppercase tracking-widest mb-1.5">Date</label>
                        <input type="date" required value={date} onChange={e => setDate(e.target.value)} className="w-full bg-slate-900 border border-slate-600 rounded-xl p-3 text-white text-sm focus:border-primary focus:ring-1 focus:ring-primary outline-none" />
                    </div>
                    <div>
                        <label className="block text-[10px] font-bold text-slate-500 uppercase tracking-widest mb-1.5">Experience (Optional)</label>
                        <textarea value={notes} onChange={e => setNotes(e.target.value)} placeholder="How was the ride? Seat location?" className="w-full bg-slate-900 border border-slate-600 rounded-xl p-3 text-white text-sm h-20 outline-none focus:border-primary" />
                    </div>
                    <button onClick={() => processLog(false)} className="w-full bg-primary font-bold py-4 rounded-2xl shadow-xl shadow-primary/30 flex items-center justify-center gap-2 active:scale-95 transition-all"><Plus size={20}/> LOG CREDIT</button>
                </div>

                {/* Ride History Section */}
                {coasterRideHistory.length > 0 && (
                    <div className="space-y-3">
                        <h3 className="text-[10px] font-bold text-slate-500 uppercase tracking-widest flex items-center gap-2 px-1">
                            <History size={14}/> Recent Laps ({coasterRideHistory.length})
                        </h3>
                        <div className="space-y-2">
                            {coasterRideHistory.map((credit) => (
                                <div key={credit.id} className="bg-slate-800/40 border border-slate-700/50 p-4 rounded-2xl flex items-center justify-between">
                                    <div className="flex items-center gap-3">
                                        <div className="bg-slate-900 p-2.5 rounded-xl text-primary border border-slate-700">
                                            <Calendar size={14}/>
                                        </div>
                                        <div>
                                            <div className="text-sm font-bold text-white">
                                                {new Date(credit.date).toLocaleDateString(undefined, { year: 'numeric', month: 'short', day: 'numeric' })}
                                            </div>
                                            {credit.notes && <div className="text-[10px] text-slate-400 italic line-clamp-1">{credit.notes}</div>}
                                        </div>
                                    </div>
                                    <button 
                                        onClick={(e) => { e.stopPropagation(); if(window.confirm('Delete this lap?')) deleteCredit(credit.id); }}
                                        className="p-2 text-slate-600 hover:text-red-400 hover:bg-red-500/10 rounded-xl transition-all"
                                    >
                                        <Trash2 size={16}/>
                                    </button>
                                </div>
                            ))}
                        </div>
                    </div>
                )}
          </div>
      );
  }

  return (
    <div className="h-full flex flex-col space-y-5 animate-fade-in">
        <div className="space-y-1">
            <h2 className="text-2xl font-black text-white italic tracking-tight">ADD <span className="text-primary">CREDIT</span></h2>
            <p className="text-[10px] font-bold text-slate-500 uppercase tracking-[0.2em]">Search our database or use AI</p>
        </div>

        <div className="flex gap-2">
            <div className="relative flex-1">
                <Search className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-500" size={18} />
                <input 
                    type="text" 
                    placeholder="Search coaster or park name..." 
                    value={searchTerm} 
                    onChange={e => setSearchTerm(e.target.value)} 
                    className="w-full bg-slate-900 border border-slate-700 rounded-2xl pl-12 py-4 text-white shadow-lg focus:border-primary focus:ring-1 focus:ring-primary outline-none text-sm transition-all" 
                />
            </div>
            <button onClick={() => setShowFilters(!showFilters)} className={clsx("p-4 rounded-2xl border transition-all active:scale-95", showFilters ? "bg-primary border-primary text-white" : "bg-slate-800 border-slate-700 text-slate-500")}><Filter size={20}/></button>
        </div>

        {/* AI Discovery Results */}
        {aiDiscoveryResults.length > 0 && (
            <div className="bg-accent/10 border border-accent/30 p-5 rounded-3xl space-y-4 animate-scale-in">
                <div className="flex items-center justify-between">
                    <div className="flex items-center gap-2">
                        <Sparkles size={16} className="text-accent" />
                        <h3 className="font-bold text-white text-sm">Discovered at {aiDiscoveryResults[0].park}</h3>
                    </div>
                    <button onClick={handleAddAllDiscovery} className="text-[10px] font-bold text-accent uppercase tracking-widest bg-accent/10 px-3 py-1.5 rounded-full border border-accent/20">Add All to DB</button>
                </div>
                <div className="grid grid-cols-1 gap-2">
                    {aiDiscoveryResults.map((res, i) => (
                        <div key={i} className="bg-slate-900/60 p-3 rounded-xl flex items-center justify-between border border-slate-700/50">
                            <div className="min-w-0 flex-1">
                                <div className="text-xs font-bold text-white truncate">{res.name}</div>
                                <div className="text-[10px] text-slate-500 truncate">{res.type} • {res.manufacturer}</div>
                            </div>
                            <button onClick={() => handleAddDiscovery(res)} className="p-2 text-accent hover:bg-accent/10 rounded-lg"><PlusCircle size={20}/></button>
                        </div>
                    ))}
                </div>
            </div>
        )}

        <div className="flex-1 overflow-y-auto space-y-3 no-scrollbar pb-20">
            {filteredCoasters.map(c => (
                <div key={c.id} onClick={() => setSelectedCoaster(c)} className="bg-slate-800/40 rounded-2xl border border-slate-700/50 flex items-stretch h-24 overflow-hidden cursor-pointer hover:bg-slate-800 transition-all hover:scale-[1.01] active:scale-[0.99] group">
                    <div className="w-24 shrink-0 bg-slate-900 border-r border-slate-700/50 overflow-hidden relative">
                        {c.imageUrl && <img src={c.imageUrl} className="w-full h-full object-cover opacity-80 group-hover:opacity-100 transition-opacity" />}
                        <div className="absolute inset-0 bg-gradient-to-t from-slate-900/60 to-transparent" />
                    </div>
                    <div className="flex-1 px-4 py-2 flex flex-col justify-center min-w-0">
                        <h3 className="font-bold text-slate-100 text-base truncate leading-tight italic">{c.name}</h3>
                        <div className="text-[10px] text-slate-500 truncate font-bold uppercase tracking-wider mt-0.5">{c.park}</div>
                        <div className="flex items-center gap-2 mt-2">
                            <span className="text-[8px] font-bold text-primary border border-primary/30 px-1.5 py-0.5 rounded uppercase tracking-widest">{c.type}</span>
                        </div>
                    </div>
                    <div className="flex items-center px-4">
                        <PlusCircle size={24} className="text-primary opacity-40 group-hover:opacity-100 transition-all" />
                    </div>
                </div>
            ))}

            {(searchTerm || filteredCoasters.length === 0) && !aiDiscoveryResults.length && (
                <div className="text-center py-8 space-y-6">
                    <div className="space-y-1">
                        <p className="text-slate-500 text-xs font-medium">Can't find it in our database?</p>
                        <p className="text-[10px] text-slate-600 uppercase font-bold tracking-widest">Try our AI or add manually</p>
                    </div>
                    <div className="grid grid-cols-1 gap-3">
                        <button 
                            onClick={handleMagicSearch} 
                            disabled={isAiSearching || !searchTerm} 
                            className={clsx(
                                "w-full py-4 rounded-2xl flex items-center justify-center gap-3 font-bold text-sm transition-all shadow-xl active:scale-95",
                                !searchTerm ? "bg-slate-800 text-slate-600 border border-slate-700" : "bg-accent text-white shadow-accent/20"
                            )}
                        >
                            {isAiSearching ? <Loader2 className="animate-spin" size={18}/> : <Sparkles size={18}/>} 
                            {isAiSearching ? 'SEARCHING THE WEB...' : 'AI MAGIC DISCOVERY'}
                        </button>
                        <button onClick={() => setIsAddingManually(true)} className="w-full bg-slate-800/50 text-slate-400 py-4 rounded-2xl font-bold text-xs uppercase tracking-[0.2em] border border-slate-700 hover:text-white transition-colors">Create Manually</button>
                    </div>
                </div>
            )}
        </div>
    </div>
  );
};

export default AddCredit;

import React, { createContext, useContext, useState, useEffect, ReactNode } from 'react';
import { User, Coaster, Credit, ViewState, WishlistEntry, RankingList } from '../types';
import { INITIAL_COASTERS, INITIAL_USERS, normalizeManufacturer, cleanName } from '../constants';
import { generateCoasterInfo, generateAppIcon } from '../services/geminiService';
import { fetchCoasterImageFromWiki } from '../services/wikipediaService';

export interface Notification {
  id: string;
  message: string;
  type: 'success' | 'error' | 'info';
}

interface AppContextType {
  activeUser: User;
  users: User[];
  coasters: Coaster[];
  credits: Credit[];
  wishlist: WishlistEntry[];
  currentView: ViewState;
  coasterListViewMode: 'CREDITS' | 'WISHLIST';
  notification: Notification | null;
  lastSearchQuery: string;

  // Actions
  switchUser: (userId: string) => void;
  addUser: (name: string, photo?: File) => void;
  updateUser: (userId: string, newName: string, photo?: File) => void;
  addCredit: (coasterId: string, date: string, notes: string, restraints: string, photo?: File) => void;
  updateCredit: (creditId: string, date: string, notes: string, restraints: string, photo?: File) => void;
  addNewCoaster: (coaster: Omit<Coaster, 'id'>) => Promise<Coaster>;
  searchOnlineCoaster: (query: string) => Promise<Partial<Coaster>[] | null>;
  generateIcon: (prompt: string) => Promise<string | null>;
  changeView: (view: ViewState) => void;
  setCoasterListViewMode: (mode: 'CREDITS' | 'WISHLIST') => void;
  deleteCredit: (creditId: string) => void;
  setLastSearchQuery: (query: string) => void;
  addToWishlist: (coasterId: string) => void;
  removeFromWishlist: (coasterId: string) => void;
  isInWishlist: (coasterId: string) => boolean;
  showNotification: (message: string, type?: 'success' | 'error' | 'info') => void;
  hideNotification: () => void;
  enrichDatabaseImages: () => Promise<void>;
  updateCoasterImage: (coasterId: string, imageUrl: string) => void;
  autoFetchCoasterImage: (coasterId: string) => Promise<string | null>;
  importData: (jsonData: any) => void;
  standardizeDatabase: () => void;

  // Ranking Actions
  updateRankings: (rankings: RankingList) => void;
}

const AppContext = createContext<AppContextType | undefined>(undefined);

const generateId = (prefix: string) => {
  const timestamp = Date.now().toString(36);
  const randomPart = Math.random().toString(36).substr(2, 9);
  return `${prefix}_${timestamp}_${randomPart}`;
};

export const AppProvider: React.FC<{ children: ReactNode }> = ({ children }) => {
  const [users, setUsers] = useState<User[]>(() => {
    const stored = localStorage.getItem('cc_users');
    return stored ? JSON.parse(stored) : INITIAL_USERS;
  });

  const [activeUser, setActiveUser] = useState<User>(() => {
    const storedId = localStorage.getItem('cc_active_user_id');
    const storedUsers = localStorage.getItem('cc_users');
    const parsedUsers = storedUsers ? JSON.parse(storedUsers) : INITIAL_USERS;
    return parsedUsers.find((u: User) => u.id === storedId) || parsedUsers[0];
  });

  const [coasters, setCoasters] = useState<Coaster[]>(() => {
    const stored = localStorage.getItem('cc_coasters');
    return stored ? JSON.parse(stored) : INITIAL_COASTERS;
  });

  const [credits, setCredits] = useState<Credit[]>(() => {
    const stored = localStorage.getItem('cc_credits');
    return stored ? JSON.parse(stored) : [];
  });

  const [wishlist, setWishlist] = useState<WishlistEntry[]>(() => {
    const stored = localStorage.getItem('cc_wishlist');
    return stored ? JSON.parse(stored) : [];
  });

  const [currentView, setCurrentView] = useState<ViewState>('DASHBOARD');
  const [coasterListViewMode, setCoasterListViewMode] = useState<'CREDITS' | 'WISHLIST'>('CREDITS');
  const [notification, setNotification] = useState<Notification | null>(null);
  const [lastSearchQuery, setLastSearchQuery] = useState('');

  useEffect(() => localStorage.setItem('cc_users', JSON.stringify(users)), [users]);
  useEffect(() => localStorage.setItem('cc_coasters', JSON.stringify(coasters)), [coasters]);
  useEffect(() => localStorage.setItem('cc_credits', JSON.stringify(credits)), [credits]);
  useEffect(() => localStorage.setItem('cc_wishlist', JSON.stringify(wishlist)), [wishlist]);
  useEffect(() => localStorage.setItem('cc_active_user_id', activeUser.id), [activeUser]);

  const showNotification = (message: string, type: 'success' | 'error' | 'info' = 'info') => {
    setNotification({ id: generateId('notif'), message, type });
    setTimeout(() => {
        setNotification(prev => (prev && prev.message === message ? null : prev));
    }, 4000);
  };

  const hideNotification = () => setNotification(null);

  const switchUser = (userId: string) => {
    const user = users.find(u => u.id === userId);
    if (user) {
        setActiveUser(user);
        showNotification(`Welcome back, ${user.name}!`);
    }
  };

  const addUser = (name: string, photo?: File) => {
    const processUser = (avatarUrl?: string) => {
        const newUser: User = {
          id: generateId('u'),
          name,
          avatarColor: ['bg-red-500', 'bg-green-500', 'bg-yellow-500', 'bg-purple-500', 'bg-pink-500', 'bg-indigo-500'][Math.floor(Math.random() * 6)],
          avatarUrl,
          rankings: { steel: [], wooden: [] }
        };
        setUsers([...users, newUser]);
        setActiveUser(newUser);
        showNotification(`Profile "${name}" created!`, 'success');
    };

    if (photo) {
        const reader = new FileReader();
        reader.onloadend = () => processUser(reader.result as string);
        reader.readAsDataURL(photo);
    } else {
        processUser();
    }
  };

  const updateUser = (userId: string, newName: string, photo?: File) => {
    const processUpdate = (avatarUrl?: string) => {
        setUsers(prevUsers => prevUsers.map(u => 
          u.id === userId ? { ...u, name: newName, ...(avatarUrl ? { avatarUrl } : {}) } : u
        ));
        if (activeUser.id === userId) {
          setActiveUser(prev => ({ ...prev, name: newName, ...(avatarUrl ? { avatarUrl } : {}) }));
        }
        showNotification("Profile updated", 'success');
    };

    if (photo) {
        const reader = new FileReader();
        reader.onloadend = () => processUpdate(reader.result as string);
        reader.readAsDataURL(photo);
    } else {
        processUpdate();
    }
  };

  const updateRankings = (rankings: RankingList) => {
    setUsers(prev => prev.map(u => u.id === activeUser.id ? { ...u, rankings } : u));
    setActiveUser(prev => ({ ...prev, rankings }));
    showNotification("Rankings updated!", 'success');
  };

  const addToWishlist = (coasterId: string) => {
    if (isInWishlist(coasterId)) {
        showNotification("Already in bucket list", 'info');
        return;
    }
    const entry: WishlistEntry = {
      id: generateId('w'),
      userId: activeUser.id,
      coasterId,
      addedAt: new Date().toISOString()
    };
    setWishlist([...wishlist, entry]);
    showNotification("Added to Bucket List", 'success');
  };

  const removeFromWishlist = (coasterId: string) => {
    setWishlist(prev => prev.filter(w => !(w.userId === activeUser.id && w.coasterId === coasterId)));
    showNotification("Removed from Bucket List", 'info');
  };

  const isInWishlist = (coasterId: string) => {
    return wishlist.some(w => w.userId === activeUser.id && w.coasterId === coasterId);
  };

  const addCredit = (coasterId: string, date: string, notes: string, restraints: string, photo?: File) => {
    if (isInWishlist(coasterId)) {
      setWishlist(prev => prev.filter(w => !(w.userId === activeUser.id && w.coasterId === coasterId)));
    }

    if (photo) {
        const reader = new FileReader();
        reader.onloadend = () => {
            const base64 = reader.result as string;
            saveCredit(coasterId, date, notes, restraints, base64);
        };
        reader.readAsDataURL(photo);
    } else {
        saveCredit(coasterId, date, notes, restraints);
    }
  };

  const saveCredit = (coasterId: string, date: string, notes: string, restraints: string, photoUrl?: string) => {
      const newCredit: Credit = {
      id: generateId('cr'),
      userId: activeUser.id,
      coasterId,
      date,
      rideCount: 1, 
      notes,
      restraints,
      photoUrl
    };
    setCredits([...credits, newCredit]);
    showNotification("Ride Logged Successfully!", 'success');
  };

  const updateCredit = (creditId: string, date: string, notes: string, restraints: string, photo?: File) => {
    const processUpdate = (photoUrl?: string) => {
      setCredits(prev => prev.map(c => {
        if (c.id === creditId) {
          return {
            ...c,
            date,
            notes,
            restraints,
            ...(photoUrl !== undefined ? { photoUrl } : {})
          };
        }
        return c;
      }));
      showNotification("Entry updated successfully", 'success');
    };

    if (photo) {
      const reader = new FileReader();
      reader.onloadend = () => {
        processUpdate(reader.result as string);
      };
      reader.readAsDataURL(photo);
    } else {
      processUpdate(); 
    }
  };

  const addNewCoaster = async (coasterData: Omit<Coaster, 'id'>): Promise<Coaster> => {
    const newId = generateId('c');
    let finalImageUrl = coasterData.imageUrl;
    if (!finalImageUrl || finalImageUrl.includes('picsum')) {
       const wikiImage = await fetchCoasterImageFromWiki(coasterData.name, coasterData.park);
       if (wikiImage) finalImageUrl = wikiImage;
    }

    const newCoaster: Coaster = { 
        ...coasterData, 
        park: cleanName(coasterData.park),
        country: cleanName(coasterData.country),
        manufacturer: normalizeManufacturer(coasterData.manufacturer),
        id: newId, 
        imageUrl: finalImageUrl 
    };
    setCoasters([...coasters, newCoaster]);
    showNotification("Added to Database", 'success');
    return newCoaster;
  };

  const searchOnlineCoaster = async (query: string) => {
    return await generateCoasterInfo(query);
  };

  const generateIcon = async (prompt: string) => {
    return await generateAppIcon(prompt);
  };

  const deleteCredit = (creditId: string) => {
    setCredits(prev => prev.filter(c => c.id !== creditId));
    showNotification("Credit deleted", 'info');
  }

  const changeView = (view: ViewState) => setCurrentView(view);

  const updateCoasterImage = (coasterId: string, imageUrl: string) => {
     setCoasters(prev => prev.map(c => c.id === coasterId ? { ...c, imageUrl } : c));
  };

  const autoFetchCoasterImage = async (coasterId: string): Promise<string | null> => {
      const coaster = coasters.find(c => c.id === coasterId);
      if (!coaster) return null;
      const imageUrl = await fetchCoasterImageFromWiki(coaster.name, coaster.park);
      if (imageUrl) {
          updateCoasterImage(coasterId, imageUrl);
          return imageUrl;
      }
      return null;
  };

  const enrichDatabaseImages = async () => {
      showNotification("Searching Wikipedia for photos...", 'info');
      const targets = coasters.filter(c => !c.imageUrl || c.imageUrl.includes('picsum'));
      let updatedCount = 0;
      const BATCH_SIZE = 5;
      for (let i = 0; i < targets.length; i += BATCH_SIZE) {
          const batch = targets.slice(i, i + BATCH_SIZE);
          const results = await Promise.all(
              batch.map(async (coaster) => {
                  const url = await fetchCoasterImageFromWiki(coaster.name, coaster.park);
                  return { id: coaster.id, url };
              })
          );
          setCoasters(prev => {
              let nextState = [...prev];
              results.forEach(res => {
                  if (res.url) {
                      const idx = nextState.findIndex(c => c.id === res.id);
                      if (idx !== -1) {
                          nextState[idx] = { ...nextState[idx], imageUrl: res.url };
                          updatedCount++;
                      }
                  }
              });
              return nextState;
          });
          await new Promise(r => setTimeout(r, 100));
      }
      if (updatedCount > 0) {
          showNotification(`Updated ${updatedCount} coasters with real photos!`, 'success');
      } else {
          showNotification(targets.length === 0 ? "Database already up to date." : "No new photos found.", 'info');
      }
  };

  const importData = (jsonData: any) => {
      try {
          const idTranslationTable: Record<string, string> = {}; 
          let mergedCoasterCount = 0;
          let addedCoasterCount = 0;
          let addedCreditCount = 0;

          if (jsonData.coasters && Array.isArray(jsonData.coasters)) {
              setCoasters(prev => {
                  const nextCoasters = [...prev];
                  jsonData.coasters.forEach((newC: Coaster) => {
                      const normName = cleanName(newC.name).toLowerCase();
                      const normPark = cleanName(newC.park).toLowerCase();
                      const existing = nextCoasters.find(c => 
                        c.id === newC.id || (cleanName(c.name).toLowerCase() === normName && cleanName(c.park).toLowerCase() === normPark)
                      );
                      if (existing) {
                        idTranslationTable[newC.id] = existing.id;
                        mergedCoasterCount++;
                      } else {
                        const newId = generateId('c');
                        idTranslationTable[newC.id] = newId;
                        nextCoasters.push({ ...newC, id: newId });
                        addedCoasterCount++;
                      }
                  });
                  return nextCoasters;
              });
          }

          if (jsonData.credits && Array.isArray(jsonData.credits)) {
              setCredits(prev => {
                  const existingIds = new Set(prev.map(c => c.id));
                  const toAdd = jsonData.credits
                    .filter((c: Credit) => !existingIds.has(c.id))
                    .map((c: Credit) => ({ ...c, userId: activeUser.id, coasterId: idTranslationTable[c.coasterId] || c.coasterId }));
                  addedCreditCount = toAdd.length;
                  return [...prev, ...toAdd];
              });
          }
          showNotification(`Import success! Added ${addedCreditCount} rides.`, 'success');
      } catch (e) {
          showNotification("Failed to import.", 'error');
      }
  };

  const standardizeDatabase = () => {
    const normalizedCoasters = coasters.map(c => ({
        ...c,
        name: cleanName(c.name),
        park: cleanName(c.park),
        manufacturer: normalizeManufacturer(c.manufacturer)
    }));
    const uniqueMap = new Map<string, string>();
    const idTranslationTable: Record<string, string> = {};
    const deduplicatedCoasters: Coaster[] = [];
    let mergedCount = 0;

    normalizedCoasters.forEach(c => {
        const key = `${c.name.toLowerCase()}|${c.park.toLowerCase()}`;
        if (uniqueMap.has(key)) {
            idTranslationTable[c.id] = uniqueMap.get(key)!;
            mergedCount++;
        } else {
            uniqueMap.set(key, c.id);
            deduplicatedCoasters.push(c);
        }
    });

    if (mergedCount > 0) {
        setCredits(prev => prev.map(cr => idTranslationTable[cr.coasterId] ? { ...cr, coasterId: idTranslationTable[cr.coasterId] } : cr));
        setCoasters(deduplicatedCoasters);
        showNotification(`Merged ${mergedCount} duplicates.`, 'success');
    }
  };

  return (
    <AppContext.Provider value={{
      activeUser, users, coasters, credits, wishlist, currentView, coasterListViewMode, notification, lastSearchQuery,
      switchUser, addUser, updateUser, addCredit, updateCredit, addNewCoaster, searchOnlineCoaster, generateIcon,
      changeView, setCoasterListViewMode, deleteCredit, addToWishlist, removeFromWishlist, isInWishlist,
      showNotification, hideNotification, setLastSearchQuery, enrichDatabaseImages, updateCoasterImage, autoFetchCoasterImage,
      importData, standardizeDatabase, updateRankings
    }}>
      {children}
    </AppContext.Provider>
  );
};

export const useAppContext = () => {
  const context = useContext(AppContext);
  if (!context) throw new Error("useAppContext must be used within AppProvider");
  return context;
};

import React, { useState, useMemo } from 'react';
