import React, { useMemo, useState, useEffect } from 'react';
import { useAppContext } from '../context/AppContext';
import { PieChart, Pie, Cell, ResponsiveContainer, Tooltip } from 'recharts';
import { Trophy, ClipboardList, Palmtree, Layers, Factory, Flag, CalendarRange, Edit2, Globe, Hash, MapPin, Navigation, ChevronRight, Zap, Star, Share2, Plus, Award, Sparkles } from 'lucide-react';
import EditCreditModal from './EditCreditModal';
import { Credit, Coaster } from '../types';
import { normalizeManufacturer } from '../constants';
import clsx from 'clsx';

type ChartMetric = 'PARK' | 'TYPE' | 'MANUFACTURER' | 'COUNTRY' | 'YEAR';

const Dashboard: React.FC = () => {
  const { credits, wishlist, coasters, activeUser, changeView, setCoasterListViewMode, setLastSearchQuery, addCredit } = useAppContext();

  const [editingCreditData, setEditingCreditData] = useState<{ credit: Credit, coaster: Coaster } | null>(null);
  const [chartMetric, setChartMetric] = useState<ChartMetric>('PARK');
  const [nearbyParks, setNearbyParks] = useState<string[]>([]);

  // Geolocation Logic
  useEffect(() => {
    if ("geolocation" in navigator) {
      navigator.geolocation.getCurrentPosition(
        (position) => {
          const uniqueParks = Array.from(new Set(coasters.map(c => c.park)));
          setNearbyParks(uniqueParks.slice(0, 3));
        },
        (error) => console.warn("Location permission denied"),
        { timeout: 10000 }
      );
    }
  }, [coasters]);

  const userCredits = useMemo(() => 
    credits
      .filter(c => c.userId === activeUser.id)
      .sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime()),
  [credits, activeUser.id]);

  const userWishlist = useMemo(() => wishlist.filter(w => w.userId === activeUser.id), [wishlist, activeUser.id]);
  const uniqueCreditsCount = useMemo(() => new Set(userCredits.map(c => c.coasterId)).size, [userCredits]);
  const totalRidesCount = userCredits.length;

  // Milestone Logic
  const milestoneLevels = [1, 10, 25, 50, 100, 250, 500];
  const nextMilestone = milestoneLevels.find(m => m > uniqueCreditsCount) || (Math.ceil((uniqueCreditsCount + 1) / 100) * 100);
  const prevMilestone = [...milestoneLevels].reverse().find(m => m <= uniqueCreditsCount) || 0;

  const progressToNext = ((uniqueCreditsCount - prevMilestone) / (nextMilestone - prevMilestone)) * 100;

  const currentLevelName = useMemo(() => {
    if (uniqueCreditsCount >= 500) return "Global Legend";
    if (uniqueCreditsCount >= 250) return "Titan of Track";
    if (uniqueCreditsCount >= 100) return "Centurion";
    if (uniqueCreditsCount >= 50) return "Pro Rider";
    if (uniqueCreditsCount >= 25) return "Expert";
    if (uniqueCreditsCount >= 10) return "Enthusiast";
    if (uniqueCreditsCount >= 1) return "Novice";
    return "Newcomer";
  }, [uniqueCreditsCount]);

  const chartData = useMemo(() => {
    const dist: Record<string, number> = {};
    const processedCoasters = new Set<string>();
    userCredits.forEach(credit => {
      if (processedCoasters.has(credit.coasterId)) return;
      processedCoasters.add(credit.coasterId);
      const coaster = coasters.find(c => c.id === credit.coasterId);
      if (coaster) {
        let key = 'Unknown';
        switch (chartMetric) {
            case 'PARK': key = coaster.park; break;
            case 'TYPE': key = coaster.type; break;
            case 'MANUFACTURER': key = normalizeManufacturer(coaster.manufacturer); break;
            case 'COUNTRY': key = coaster.country; break;
            case 'YEAR': key = new Date(credit.date).getFullYear().toString(); break;
        }
        dist[key] = (dist[key] || 0) + 1;
      }
    });
    return Object.entries(dist).map(([name, value]) => ({ name, value })).sort((a, b) => b.value - a.value).slice(0, 8);
  }, [userCredits, coasters, chartMetric]);

  const COLORS = ['#0ea5e9', '#8b5cf6', '#f43f5e', '#10b981', '#f59e0b', '#6366f1', '#ec4899', '#14b8a6'];
  const recentCredit = userCredits.length > 0 ? userCredits[0] : null;
  const recentCoaster = recentCredit ? coasters.find(c => c.id === recentCredit.coasterId) : null;

  const handleQuickLog = (e: React.MouseEvent) => {
      e.stopPropagation();
      if (recentCoaster) {
          addCredit(recentCoaster.id, new Date().toISOString().split('T')[0], 'Marathon ride!', '');
      }
  };

  const MetricButton = ({ mode, label, icon: Icon }: { mode: ChartMetric, label: string, icon: React.ElementType }) => (
      <button
        onClick={() => setChartMetric(mode)}
        className={clsx(
            "flex items-center gap-1.5 px-3 py-1.5 rounded-lg text-[10px] font-bold uppercase tracking-wide transition-all border",
            chartMetric === mode ? "bg-primary text-white border-primary shadow-lg shadow-primary/20" : "bg-slate-900 border-slate-700 text-slate-400 hover:text-white"
        )}
      >
          <Icon size={12} />
          {label}
      </button>
  );

  return (
    <div className="space-y-6 animate-fade-in pb-10">

      {/* 1. Milestone Progress Card - Actionable & Highly Visual */}
      <div 
        onClick={() => changeView('MILESTONES')}
        className="group relative bg-slate-800/60 backdrop-blur-md border border-slate-700 p-6 rounded-[32px] overflow-hidden cursor-pointer active:scale-[0.98] transition-all shadow-2xl"
      >
          {/* Animated Glow Background */}
          <div className="absolute top-0 right-0 w-32 h-32 bg-primary/20 blur-[60px] group-hover:bg-primary/40 transition-all rounded-full" />

          <div className="flex items-center justify-between relative z-10">
              <div className="space-y-2">
                  <div className="flex items-center gap-2">
                    <span className="bg-primary/20 text-primary px-2.5 py-1 rounded-lg text-[10px] font-black uppercase tracking-[0.2em] border border-primary/30">
                        {currentLevelName}
                    </span>
                    <Sparkles size={14} className="text-amber-400 animate-pulse" />
                  </div>
                  <h3 className="text-3xl font-black text-white italic tracking-tighter">
                    {uniqueCreditsCount} <span className="text-slate-500 text-xl font-bold">/ {nextMilestone}</span>
                  </h3>
                  <p className="text-[10px] font-bold text-slate-400 uppercase tracking-widest flex items-center gap-1">
                    Progress to Next Badge <ChevronRight size={10} className="text-primary" />
                  </p>
              </div>

              <div className="relative w-20 h-20">
                  <div className="absolute inset-0 bg-primary/10 rounded-full animate-ping opacity-20" />
                  <svg className="w-full h-full transform -rotate-90">
                      <circle cx="40" cy="40" r="34" stroke="currentColor" strokeWidth="8" fill="transparent" className="text-slate-900" />
                      <circle cx="40" cy="40" r="34" stroke="currentColor" strokeWidth="8" fill="transparent" strokeDasharray={2 * Math.PI * 34} strokeDashoffset={2 * Math.PI * 34 * (1 - progressToNext / 100)} className="text-primary transition-all duration-1000 ease-out" strokeLinecap="round" />
                  </svg>
                  <div className="absolute inset-0 flex items-center justify-center">
                      <Award size={28} className="text-primary drop-shadow-[0_0_10px_rgba(14,165,233,0.5)]" />
                  </div>
              </div>
          </div>

          <div className="mt-6 flex items-center gap-3">
              <div className="flex-1 h-2 bg-slate-900 rounded-full overflow-hidden">
                  <div className="h-full bg-gradient-to-r from-primary via-primary/80 to-accent transition-all duration-1000" style={{ width: `${progressToNext}%` }} />
              </div>
              <span className="text-[10px] font-black text-slate-500 italic">{Math.round(progressToNext)}%</span>
          </div>
      </div>

      {/* 2. Rankings Quick-Access */}
      <button 
          onClick={() => changeView('RANKINGS')}
          className="w-full bg-gradient-to-br from-amber-500/20 via-yellow-600/10 to-transparent border border-amber-500/30 p-4 rounded-2xl flex items-center justify-between group active:scale-[0.98] transition-all shadow-xl"
      >
          <div className="flex items-center gap-4">
              <div className="bg-gradient-to-br from-amber-400 to-yellow-600 p-2.5 rounded-xl text-slate-900 shadow-lg">
                  <Trophy size={22} fill="currentColor" />
              </div>
              <div className="text-left">
                  <h3 className="font-bold text-white text-base leading-tight">My Top 10 Rankings</h3>
                  <p className="text-[10px] text-amber-500/80 font-bold uppercase tracking-widest mt-0.5">Manage Your Credits</p>
              </div>
          </div>
          <ChevronRight size={18} className="text-amber-500/50 group-hover:text-amber-500 group-hover:translate-x-1 transition-all" />
      </button>

      {/* 3. Main Stats Grid */}
      <div className="grid grid-cols-2 gap-4">
        <div 
            className="bg-slate-800 rounded-2xl p-5 shadow-lg border border-slate-700 relative overflow-hidden cursor-pointer active:scale-95 transition-transform group"
            onClick={() => { setCoasterListViewMode('CREDITS'); changeView('COASTER_LIST'); }}
        >
            <div className="relative z-10">
                <h2 className="text-slate-400 text-[10px] font-bold uppercase tracking-wider">Unique Credits</h2>
                <div className="text-4xl font-black text-white mt-1 tracking-tighter">{uniqueCreditsCount}</div>
                <div className="flex items-center gap-1 mt-2 text-[10px] font-bold text-primary bg-primary/10 w-fit px-2 py-1 rounded-md">
                    <Zap size={10} /> {totalRidesCount} TOTAL RIDES
                </div>
            </div>
        </div>

        <div 
            className="bg-slate-800 rounded-2xl p-5 shadow-lg border border-slate-700 relative overflow-hidden cursor-pointer active:scale-95 transition-transform group" 
            onClick={() => { setCoasterListViewMode('WISHLIST'); changeView('COASTER_LIST'); }}
        >
            <div className="relative z-10">
                 <h2 className="text-slate-400 text-[10px] font-bold uppercase tracking-wider">Bucket List</h2>
                 <div className="text-4xl font-black text-white mt-1 tracking-tighter">{userWishlist.length}</div>
                 <p className="text-amber-500 mt-1 text-[10px] font-bold flex items-center gap-1">GO TO LIST <ChevronRight size={10} /></p>
            </div>
        </div>
      </div>

      {/* 4. Quick Log / Last Ridden (UX SPEED) */}
      {recentCoaster && (
        <div className="relative group">
            <div 
                onClick={() => { setEditingCreditData({ credit: recentCredit!, coaster: recentCoaster }); }}
                className="bg-slate-800 p-4 rounded-2xl border border-slate-700 flex gap-4 items-center cursor-pointer hover:bg-slate-750 transition-all active:scale-[0.99]"
            >
                <div className="w-16 h-16 rounded-xl overflow-hidden shrink-0 shadow-lg border border-slate-600">
                    <img src={recentCoaster.imageUrl} alt={recentCoaster.name} className="w-full h-full object-cover" />
                </div>
                <div className="flex-1 min-w-0">
                    <div className="text-[10px] text-primary uppercase font-bold tracking-widest mb-0.5">Last Logged</div>
                    <div className="font-bold text-lg text-white truncate leading-tight">{recentCoaster.name}</div>
                    <div className="text-xs text-slate-500 truncate">{recentCoaster.park}</div>
                </div>
                <button 
                    onClick={handleQuickLog}
                    className="bg-primary/10 hover:bg-primary text-primary hover:text-white p-3 rounded-xl transition-all border border-primary/20 flex flex-col items-center gap-1 shrink-0"
                >
                    <Plus size={20} />
                    <span className="text-[8px] font-bold uppercase">Log Again</span>
                </button>
            </div>
        </div>
      )}

      {/* 5. Statistics Panel */}
      <div className="bg-slate-800 p-5 rounded-2xl border border-slate-700 shadow-xl">
            <div className="flex justify-between items-center mb-6">
                <h3 className="text-lg font-bold text-white flex items-center gap-2">Insights</h3>
                <div className="flex gap-1 overflow-x-auto no-scrollbar max-w-[60%]">
                    <MetricButton mode="PARK" label="Park" icon={Palmtree} />
                    <MetricButton mode="TYPE" label="Type" icon={Layers} />
                    <MetricButton mode="MANUFACTURER" label="Brand" icon={Factory} />
                </div>
            </div>

            {uniqueCreditsCount > 0 ? (
                <div className="flex flex-col sm:flex-row items-center gap-6">
                    <div className="h-40 w-40 relative shrink-0">
                        <ResponsiveContainer width="100%" height="100%">
                            <PieChart>
                                <Pie data={chartData} cx="50%" cy="50%" innerRadius={45} outerRadius={65} paddingAngle={4} dataKey="value" stroke="none">
                                    {chartData.map((entry, index) => <Cell key={`cell-${index}`} fill={COLORS[index % COLORS.length]} />)}
                                </Pie>
                                <Tooltip contentStyle={{ backgroundColor: '#0f172a', border: 'none', borderRadius: '12px' }} />
                            </PieChart>
                        </ResponsiveContainer>
                    </div>
                    <div className="flex-1 grid grid-cols-1 gap-2 w-full">
                        {chartData.slice(0, 4).map((entry, index) => (
                            <div key={entry.name} className="flex items-center justify-between text-xs bg-slate-900/40 p-2.5 rounded-xl border border-slate-700/50">
                                <div className="flex items-center gap-3 truncate">
                                    <div className="w-2 h-2 rounded-full shrink-0" style={{ backgroundColor: COLORS[index % COLORS.length] }}></div>
                                    <span className="text-slate-300 truncate font-medium">{entry.name}</span>
                                </div>
                                <span className="font-bold text-white">{entry.value}</span>
                            </div>
                        ))}
                    </div>
                </div>
            ) : (
                <div className="h-40 w-full flex flex-col items-center justify-center text-slate-500 border-2 border-dashed border-slate-700 rounded-2xl bg-slate-800/50">
                    <p className="text-xs font-medium">No data to visualize yet</p>
                </div>
            )}
      </div>

      {editingCreditData && <EditCreditModal credit={editingCreditData.credit} coaster={editingCreditData.coaster} onClose={() => setEditingCreditData(null)} />}
    </div>
  );
};

export default Dashboard;

import React, { useMemo } from 'react';
import { useAppContext } from '../context/AppContext';
import { ArrowLeft, Award, CheckCircle2, Lock, Sparkles, Star, Trophy, Zap, Calendar, Share2, MapPin } from 'lucide-react';
import clsx from 'clsx';

interface MilestoneDefinition {
  threshold: number;
  title: string;
  description: string;
  icon: React.ElementType;
  color: string;
}

const MILESTONES: MilestoneDefinition[] = [
  { threshold: 1, title: 'First Drop', description: 'Log your very first roller coaster credit.', icon: Zap, color: 'from-blue-400 to-cyan-500' },
  { threshold: 10, title: 'Double Down', description: 'Reach 10 unique credits in your collection.', icon: Star, color: 'from-emerald-400 to-green-600' },
  { threshold: 25, title: 'Silver Streak', description: 'Hit 25 unique credits. You\'re an enthusiast now!', icon: Trophy, color: 'from-slate-300 to-slate-500' },
  { threshold: 50, title: 'Half Century', description: '50 unique coasters ridden. Absolute pro status.', icon: Award, color: 'from-amber-400 to-orange-600' },
  { threshold: 100, title: 'Centurion', description: 'The legendary 100 club. A true coaster legend.', icon: Sparkles, color: 'from-purple-500 to-pink-600' },
  { threshold: 250, title: 'Titan of Track', description: '250 unique credits. Worldwide respect.', icon: Trophy, color: 'from-red-500 to-rose-700' },
  { threshold: 500, title: 'Global Legend', description: '500 unique credits. You\'ve seen it all.', icon: Trophy, color: 'from-indigo-600 to-violet-900' },
];

const Milestones: React.FC = () => {
  const { credits, activeUser, changeView, coasters } = useAppContext();

  const userCredits = useMemo(() => 
    credits
      .filter(c => c.userId === activeUser.id)
      .sort((a, b) => new Date(a.date).getTime() - new Date(b.date).getTime()),
  [credits, activeUser.id]);

  const uniqueCount = useMemo(() => {
    const seen = new Set<string>();
    const sequence: { count: number, date: string, coasterName: string }[] = [];

    userCredits.forEach(c => {
        if (!seen.has(c.coasterId)) {
            seen.add(c.coasterId);
            const coaster = coasters.find(item => item.id === c.coasterId);
            sequence.push({ 
                count: seen.size, 
                date: c.date, 
                coasterName: coaster?.name || 'Unknown' 
            });
        }
    });
    return sequence;
  }, [userCredits, coasters]);

  const currentUniqueCount = uniqueCount.length;

  return (
    <div className="animate-fade-in pb-12 space-y-6">
      {/* Header */}
      <div className="flex items-center gap-4">
          <button 
            onClick={() => changeView('DASHBOARD')}
            className="bg-slate-800 p-3 rounded-2xl border border-slate-700 text-slate-400 hover:text-white transition-all active:scale-95 shadow-lg"
          >
            <ArrowLeft size={20} />
          </button>
          <div>
            <h2 className="text-2xl font-black text-white italic tracking-tight">MILESTONES</h2>
            <p className="text-[10px] font-bold text-slate-500 uppercase tracking-widest">Track your legacy</p>
          </div>
      </div>

      {/* Stats Hero */}
      <div className="bg-slate-800/40 border border-slate-700 p-8 rounded-[40px] text-center space-y-2 relative overflow-hidden">
          <div className="absolute inset-0 bg-primary/5 blur-3xl rounded-full translate-y-1/2" />
          <h3 className="text-6xl font-black text-white italic tracking-tighter drop-shadow-2xl">{currentUniqueCount}</h3>
          <p className="text-xs font-bold text-primary uppercase tracking-[0.3em]">Credits Unlocked</p>
      </div>

      {/* Milestone List */}
      <div className="space-y-4 relative">
          {/* Vertical Track Line */}
          <div className="absolute left-10 top-10 bottom-10 w-1 bg-slate-800 rounded-full" />

          {MILESTONES.map((m, i) => {
              const isUnlocked = currentUniqueCount >= m.threshold;
              const achievementInfo = uniqueCount.find(item => item.count === m.threshold);
              const Icon = m.icon;

              return (
                  <div key={i} className={clsx(
                    "relative flex gap-6 items-start transition-all duration-700",
                    isUnlocked ? "opacity-100 translate-x-0" : "opacity-40 grayscale"
                  )}>
                      {/* Milestone Badge Icon */}
                      <div className={clsx(
                        "relative z-10 w-20 h-20 rounded-[28px] shrink-0 flex items-center justify-center border-4 shadow-xl transition-all",
                        isUnlocked 
                            ? `bg-gradient-to-br ${m.color} border-white/20 rotate-3 scale-110` 
                            : "bg-slate-900 border-slate-800 scale-90"
                      )}>
                          {isUnlocked ? (
                              <Icon size={32} className="text-white drop-shadow-md" />
                          ) : (
                              <Lock size={28} className="text-slate-700" />
                          )}

                          {/* Indicator Checkmark */}
                          {isUnlocked && (
                              <div className="absolute -top-2 -right-2 bg-emerald-500 text-white p-1 rounded-full border-2 border-slate-900 shadow-lg">
                                  <CheckCircle2 size={12} />
                              </div>
                          )}
                      </div>

                      {/* Content */}
                      <div className="flex-1 pt-2 space-y-1">
                          <div className="flex items-center justify-between">
                            <h4 className={clsx(
                                "text-lg font-black italic tracking-tight leading-none",
                                isUnlocked ? "text-white" : "text-slate-600"
                            )}>
                                {m.threshold} {m.title.toUpperCase()}
                            </h4>
                            {isUnlocked && (
                                <button className="text-slate-500 hover:text-primary transition-colors">
                                    <Share2 size={16} />
                                </button>
                            )}
                          </div>

                          <p className="text-xs text-slate-400 leading-relaxed font-medium">
                              {m.description}
                          </p>

                          {isUnlocked && achievementInfo && (
                              <div className="pt-2 flex items-center gap-3">
                                  <div className="bg-slate-800/50 px-3 py-1.5 rounded-xl border border-slate-700/50 flex items-center gap-2">
                                      <Calendar size={12} className="text-primary" />
                                      <span className="text-[10px] font-bold text-slate-300">
                                          {new Date(achievementInfo.date).toLocaleDateString(undefined, { month: 'short', day: 'numeric', year: 'numeric' })}
                                      </span>
                                  </div>
                                  <div className="flex-1 truncate bg-slate-800/50 px-3 py-1.5 rounded-xl border border-slate-700/50 flex items-center gap-2">
                                      <MapPin size={12} className="text-accent" />
                                      <span className="text-[10px] font-bold text-slate-300 truncate">
                                          {achievementInfo.coasterName}
                                      </span>
                                  </div>
                              </div>
                          )}

                          {!isUnlocked && (
                              <div className="pt-1">
                                  <div className="text-[9px] font-black text-slate-700 uppercase tracking-widest">
                                      Need {m.threshold - currentUniqueCount} more credits
                                  </div>
                              </div>
                          )}
                      </div>
                  </div>
              );
          })}
      </div>
    </div>
  );
};

export default Milestones;

import React, { useState, useMemo } from 'react';
import { useAppContext } from '../context/AppContext';
import { Coaster, CoasterType } from '../types';
import { Search, Plus, Calendar, Sparkles, Loader2, Filter, Bookmark, BookmarkCheck, PlusCircle, ArrowLeft as BackIcon, Zap, Ruler, ArrowUp, History, Trash2, Clock, CheckCircle2, Globe, Info, X, ZapOff } from 'lucide-react';
import { cleanName } from '../constants';
import clsx from 'clsx';

const normalizeText = (text: string) => cleanName(text).toLowerCase();

const AddCredit: React.FC = () => {
  const { coasters, addCredit, deleteCredit, addNewCoaster, addMultipleCoasters, searchOnlineCoaster, credits, activeUser, addToWishlist, removeFromWishlist, isInWishlist, lastSearchQuery, setLastSearchQuery, showNotification } = useAppContext();

  const searchTerm = lastSearchQuery;
  const setSearchTerm = setLastSearchQuery;
  const [selectedCoaster, setSelectedCoaster] = useState<Coaster | null>(null);
  const [isAiSearching, setIsAiSearching] = useState(false);
  const [isAddingManually, setIsAddingManually] = useState(false);
  const [aiDiscoveryResults, setAiDiscoveryResults] = useState<Partial<Coaster>[]>([]);

  const [manualCoasterData, setManualCoasterData] = useState({ name: '', park: '', country: '', manufacturer: '', type: 'Steel' as CoasterType });
  const [filterType, setFilterType] = useState<string>('All');
  const [showFilters, setShowFilters] = useState(false);
  const [hideRidden, setHideRidden] = useState(false);
  const [date, setDate] = useState<string>(new Date().toISOString().split('T')[0]);
  const [notes, setNotes] = useState('');
  const [restraints, setRestraints] = useState('');
  const [photo, setPhoto] = useState<File | undefined>(undefined);

  // Detect if we are in a "Park Marathon" (filtering by a specific park)
  const isMarathonMode = useMemo(() => {
    if (!searchTerm) return false;
    const matches = coasters.filter(c => normalizeText(c.park) === normalizeText(searchTerm));
    return matches.length > 0 && matches.length === coasters.filter(c => normalizeText(c.park).includes(normalizeText(searchTerm))).length;
  }, [searchTerm, coasters]);

  const filteredCoasters = useMemo(() => {
    let result = coasters;
    if (searchTerm) {
        const normalizedSearch = normalizeText(searchTerm);
        result = result.filter(c => normalizeText(c.name).includes(normalizedSearch) || normalizeText(c.park).includes(normalizedSearch));
    }
    if (filterType !== 'All') result = result.filter(c => c.type === filterType);
    if (hideRidden) result = result.filter(c => !credits.some(cr => cr.userId === activeUser.id && cr.coasterId === c.id));
    return result.sort((a, b) => a.name.localeCompare(b.name));
  }, [coasters, searchTerm, filterType, hideRidden, credits, activeUser.id]);

  const marathonStats = useMemo(() => {
      if (!isMarathonMode) return null;
      const parkCoasters = coasters.filter(c => normalizeText(c.park) === normalizeText(searchTerm));
      const riddenCount = parkCoasters.filter(c => credits.some(cr => cr.userId === activeUser.id && cr.coasterId === c.id)).length;
      return { total: parkCoasters.length, ridden: riddenCount };
  }, [isMarathonMode, searchTerm, coasters, credits, activeUser.id]);

  const coasterRideHistory = useMemo(() => {
    if (!selectedCoaster) return [];
    return credits
      .filter(c => c.userId === activeUser.id && c.coasterId === selectedCoaster.id)
      .sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime());
  }, [selectedCoaster, credits, activeUser.id]);

  const handleMagicSearch = async () => {
      if (!searchTerm) return;
      setIsAiSearching(true);
      setAiDiscoveryResults([]);
      const results = await searchOnlineCoaster(searchTerm);
      setIsAiSearching(false);

      if (results && results.length > 0) {
          if (results.length === 1) {
              const res = results[0];
              if (window.confirm(`Found: ${res.name} at ${res.park}. Add to database?`)) {
                  const newC = await addNewCoaster(res as Omit<Coaster, 'id'>);
                  setSelectedCoaster(newC);
              }
          } else {
              setAiDiscoveryResults(results);
          }
      } else {
          showNotification("No coasters found. Try refining your search.", "info");
      }
  };

  const handleAddDiscovery = async (item: Partial<Coaster>) => {
      const newC = await addNewCoaster(item as Omit<Coaster, 'id'>);
      setAiDiscoveryResults(prev => prev.filter(p => p.name !== item.name));
      setSelectedCoaster(newC);
  };

  const handleAddAllDiscovery = async () => {
      if (aiDiscoveryResults.length === 0) return;
      const itemsToAdd = aiDiscoveryResults.map(item => item as Omit<Coaster, 'id'>);
      await addMultipleCoasters(itemsToAdd);
      setAiDiscoveryResults([]);
  };

  const handleBulkLogDiscovery = async () => {
      if (aiDiscoveryResults.length === 0) return;
      if (!window.confirm(`Add all ${aiDiscoveryResults.length} rides to your log for ${date}?`)) return;

      const itemsToAdd = aiDiscoveryResults.map(item => item as Omit<Coaster, 'id'>);
      // We need IDs to log credits, so we add them to DB first
      // The AppContext needs to return the new coasters to log them immediately
      // For now, we'll just add them to DB and suggest user logs them from the park view
      await addMultipleCoasters(itemsToAdd);
      setSearchTerm(aiDiscoveryResults[0].park || '');
      setAiDiscoveryResults([]);
      showNotification("Lineup added! You can now log each ride in one tap.", "success");
  };

  const handleManualSubmit = async (e: React.FormEvent) => {
      e.preventDefault();
      const newC = await addNewCoaster({ ...manualCoasterData, isCustom: true });
      setIsAddingManually(false);
      setSelectedCoaster(newC);
  };

  const processLog = (filterByPark: boolean) => {
    if (selectedCoaster) {
        addCredit(selectedCoaster.id, date, notes, restraints, photo);
        if (filterByPark) {
            setSearchTerm(selectedCoaster.park);
        }
        setNotes(''); setRestraints(''); setPhoto(undefined);
        setSelectedCoaster(null); // ALWAYS return to list for multi-ride logging
    }
  };

  const isSelectedWishlisted = selectedCoaster ? isInWishlist(selectedCoaster.id) : false;

  if (isAddingManually) {
      return (
          <div className="animate-fade-in pb-20">
              <div className="flex items-center gap-3 mb-6">
                <button onClick={() => setIsAddingManually(false)} className="p-2 rounded-xl bg-slate-800 border border-slate-700 text-slate-400"><BackIcon size={20}/></button>
                <h2 className="text-xl font-bold">Add Coaster Manually</h2>
              </div>
              <form onSubmit={handleManualSubmit} className="bg-slate-800 p-6 rounded-2xl border border-slate-700 space-y-4">
                  <input required placeholder="Coaster Name" value={manualCoasterData.name} onChange={e => setManualCoasterData({...manualCoasterData, name: e.target.value})} className="w-full bg-slate-900 border border-slate-600 rounded-xl p-3 text-white" />
                  <input required placeholder="Park Name" value={manualCoasterData.park} onChange={e => setManualCoasterData({...manualCoasterData, park: e.target.value})} className="w-full bg-slate-900 border border-slate-600 rounded-xl p-3 text-white" />
                  <div className="pt-4"><button type="submit" className="w-full bg-primary py-3.5 rounded-xl font-bold">Save & Log Ride</button></div>
              </form>
          </div>
      );
  }

  if (selectedCoaster) {
      return (
          <div className="animate-fade-in pb-24 space-y-4">
                <div className="sticky top-0 -mx-4 -mt-4 p-4 z-20 bg-slate-900/95 backdrop-blur-md border-b border-slate-700/50 flex gap-2">
                    <button onClick={() => setSelectedCoaster(null)} className="p-3 rounded-xl bg-slate-800 border border-slate-700 text-slate-400"><BackIcon size={20}/></button>
                    <button onClick={() => processLog(true)} className="flex-1 bg-emerald-500/10 text-emerald-400 font-bold py-3 rounded-xl border border-emerald-500/30 flex items-center justify-center gap-2">Log & Continue at Park</button>
                </div>

                {selectedCoaster.imageUrl && (
                    <div className="w-full h-48 rounded-2xl overflow-hidden shadow-lg border border-slate-700 relative">
                        <img src={selectedCoaster.imageUrl} alt={selectedCoaster.name} className="w-full h-full object-cover" />
                        <div className="absolute inset-0 bg-gradient-to-t from-slate-950 via-transparent to-transparent" />
                        <div className="absolute bottom-4 left-4">
                            <h2 className="text-3xl font-black text-white leading-tight italic drop-shadow-md">{selectedCoaster.name}</h2>
                            <div className="text-slate-300 text-sm font-bold flex items-center gap-1 uppercase tracking-wider"><Globe size={14} className="text-primary"/> {selectedCoaster.park}</div>
                        </div>
                    </div>
                )}

                <div className="bg-slate-800 p-5 rounded-3xl border border-slate-700 space-y-4 shadow-xl">
                    <div className="flex items-center justify-between mb-2">
                        <h3 className="font-bold text-white flex items-center gap-2 text-sm uppercase tracking-widest text-slate-400"><Clock size={16} className="text-primary"/> Quick Log</h3>
                    </div>
                    <div className="grid grid-cols-1 gap-4">
                        <div>
                            <label className="block text-[10px] font-bold text-slate-500 uppercase tracking-widest mb-1.5">Date</label>
                            <input type="date" required value={date} onChange={e => setDate(e.target.value)} className="w-full bg-slate-900 border border-slate-600 rounded-xl p-3 text-white text-sm focus:border-primary focus:ring-1 focus:ring-primary outline-none" />
                        </div>
                        <div>
                            <label className="block text-[10px] font-bold text-slate-500 uppercase tracking-widest mb-1.5">Experience (Optional)</label>
                            <textarea value={notes} onChange={e => setNotes(e.target.value)} placeholder="How was the ride? Seat location?" className="w-full bg-slate-900 border border-slate-600 rounded-xl p-3 text-white text-sm h-20 outline-none focus:border-primary" />
                        </div>
                    </div>
                    <button onClick={() => processLog(false)} className="w-full bg-primary font-bold py-4 rounded-2xl shadow-xl shadow-primary/30 flex items-center justify-center gap-2 active:scale-95 transition-all"><Plus size={20}/> LOG CREDIT</button>
                </div>

                {/* Ride History Section */}
                {coasterRideHistory.length > 0 && (
                    <div className="space-y-3">
                        <h3 className="text-[10px] font-bold text-slate-500 uppercase tracking-widest flex items-center gap-2 px-1">
                            <History size={14}/> Recent Laps ({coasterRideHistory.length})
                        </h3>
                        <div className="space-y-2">
                            {coasterRideHistory.map((credit) => (
                                <div key={credit.id} className="bg-slate-800/40 border border-slate-700/50 p-4 rounded-2xl flex items-center justify-between">
                                    <div className="flex items-center gap-3">
                                        <div className="bg-slate-900 p-2.5 rounded-xl text-primary border border-slate-700">
                                            <Calendar size={14}/>
                                        </div>
                                        <div>
                                            <div className="text-sm font-bold text-white">
                                                {new Date(credit.date).toLocaleDateString(undefined, { year: 'numeric', month: 'short', day: 'numeric' })}
                                            </div>
                                            {credit.notes && <div className="text-[10px] text-slate-400 italic line-clamp-1">{credit.notes}</div>}
                                        </div>
                                    </div>
                                    <button 
                                        onClick={(e) => { e.stopPropagation(); if(window.confirm('Delete this lap?')) deleteCredit(credit.id); }}
                                        className="p-2 text-slate-600 hover:text-red-400 hover:bg-red-500/10 rounded-xl transition-all"
                                    >
                                        <Trash2 size={16}/>
                                    </button>
                                </div>
                            ))}
                        </div>
                    </div>
                )}
          </div>
      );
  }

  return (
    <div className="h-full flex flex-col space-y-5 animate-fade-in">

        {/* Marathon Mode Header */}
        {isMarathonMode && marathonStats && (
            <div className="bg-gradient-to-r from-emerald-600 to-teal-700 rounded-2xl p-4 flex items-center justify-between shadow-lg shadow-emerald-900/20 border border-emerald-500/30 animate-scale-in">
                <div className="flex items-center gap-3">
                    <div className="bg-white/20 p-2 rounded-xl">
                        <Zap size={18} className="text-white fill-white" />
                    </div>
                    <div>
                        <h3 className="text-sm font-black text-white italic leading-tight uppercase tracking-tight">Marathon Mode</h3>
                        <p className="text-[10px] text-emerald-100 font-bold uppercase tracking-widest">{searchTerm}</p>
                    </div>
                </div>
                <div className="flex items-center gap-4">
                    <div className="text-right">
                        <div className="text-xs font-black text-white">{marathonStats.ridden} / {marathonStats.total}</div>
                        <div className="text-[8px] text-emerald-100 font-bold uppercase tracking-widest">Completed</div>
                    </div>
                    <button onClick={() => setSearchTerm('')} className="bg-white/10 hover:bg-white/20 p-1.5 rounded-lg text-white transition-colors">
                        <X size={16} />
                    </button>
                </div>
            </div>
        )}

        {!isMarathonMode && (
            <div className="space-y-1">
                <h2 className="text-2xl font-black text-white italic tracking-tight">ADD <span className="text-primary">CREDIT</span></h2>
                <p className="text-[10px] font-bold text-slate-500 uppercase tracking-[0.2em]">Search our database or use AI</p>
            </div>
        )}

        <div className="space-y-3">
          <div className="flex gap-2">
              <div className="relative flex-1">
                  <Search className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-500" size={18} />
                  <input 
                      type="text" 
                      placeholder="Search coaster or park name..." 
                      value={searchTerm} 
                      onChange={e => setSearchTerm(e.target.value)} 
                      className="w-full bg-slate-900 border border-slate-700 rounded-2xl pl-12 py-4 text-white shadow-lg focus:border-primary focus:ring-1 focus:ring-primary outline-none text-sm transition-all" 
                  />
              </div>
              <button onClick={() => setShowFilters(!showFilters)} className={clsx("p-4 rounded-2xl border transition-all active:scale-95", showFilters ? "bg-primary border-primary text-white" : "bg-slate-800 border-slate-700 text-slate-500")}><Filter size={20}/></button>
          </div>
          {!isMarathonMode && (
            <div className="flex items-center gap-2 px-2 text-slate-500 bg-slate-800/20 p-2 rounded-xl border border-slate-700/30">
                <Info size={14} className="text-primary shrink-0" />
                <span className="text-[10px] font-medium leading-tight">Pro Tip: Type a <strong className="text-white">park</strong> (e.g. 'Cedar Point') to see all coasters at once.</span>
            </div>
          )}
        </div>

        {/* AI Discovery Results */}
        {aiDiscoveryResults.length > 0 && (
            <div className="bg-accent/10 border border-accent/30 p-5 rounded-3xl space-y-4 animate-scale-in">
                <div className="flex items-center justify-between">
                    <div className="flex items-center gap-2">
                        <Sparkles size={16} className="text-accent" />
                        <h3 className="font-bold text-white text-sm">Discovered at {aiDiscoveryResults[0].park}</h3>
                    </div>
                    <div className="flex gap-2">
                        <button onClick={handleBulkLogDiscovery} className="text-[8px] font-black text-white bg-emerald-600 px-3 py-1.5 rounded-lg hover:bg-emerald-500 transition-colors uppercase tracking-widest shadow-lg shadow-emerald-900/20">DB + Log All</button>
                        <button onClick={handleAddAllDiscovery} className="text-[8px] font-black text-white bg-slate-700 px-3 py-1.5 rounded-lg hover:bg-slate-600 transition-colors uppercase tracking-widest">Add DB Only</button>
                    </div>
                </div>
                <div className="grid grid-cols-1 gap-2">
                    {aiDiscoveryResults.map((res, i) => (
                        <div key={i} className="bg-slate-900/60 p-3 rounded-xl flex items-center justify-between border border-slate-700/50">
                            <div className="min-w-0 flex-1">
                                <div className="text-xs font-bold text-white truncate">{res.name}</div>
                                <div className="text-[10px] text-slate-500 truncate">{res.type} • {res.manufacturer}</div>
                            </div>
                            <button onClick={() => handleAddDiscovery(res)} className="p-2 text-accent hover:bg-accent/10 rounded-lg"><PlusCircle size={20}/></button>
                        </div>
                    ))}
                </div>
            </div>
        )}

        <div className="flex-1 overflow-y-auto space-y-3 no-scrollbar pb-20">
            {filteredCoasters.map(c => {
                const isRidden = credits.some(cr => cr.userId === activeUser.id && cr.coasterId === c.id);
                return (
                    <div key={c.id} onClick={() => setSelectedCoaster(c)} className={clsx("bg-slate-800/40 rounded-2xl border flex items-stretch h-24 overflow-hidden cursor-pointer hover:bg-slate-800 transition-all hover:scale-[1.01] active:scale-[0.99] group", isRidden ? "border-emerald-500/20" : "border-slate-700/50")}>
                        <div className="w-24 shrink-0 bg-slate-900 border-r border-slate-700/50 overflow-hidden relative">
                            {c.imageUrl && <img src={c.imageUrl} className={clsx("w-full h-full object-cover transition-opacity", isRidden ? "opacity-40" : "opacity-80 group-hover:opacity-100")} />}
                            <div className="absolute inset-0 bg-gradient-to-t from-slate-900/60 to-transparent" />
                            {isRidden && <div className="absolute inset-0 flex items-center justify-center"><CheckCircle2 size={24} className="text-emerald-500 drop-shadow-md" /></div>}
                        </div>
                        <div className="flex-1 px-4 py-2 flex flex-col justify-center min-w-0">
                            <h3 className={clsx("font-bold text-base truncate leading-tight italic", isRidden ? "text-slate-400" : "text-slate-100")}>{c.name}</h3>
                            <div className="text-[10px] text-slate-500 truncate font-bold uppercase tracking-wider mt-0.5">{c.park}</div>
                            <div className="flex items-center gap-2 mt-2">
                                <span className="text-[8px] font-bold text-primary border border-primary/30 px-1.5 py-0.5 rounded uppercase tracking-widest">{c.type}</span>
                            </div>
                        </div>
                        <div className="flex items-center px-4">
                            <PlusCircle size={24} className={clsx("transition-all", isRidden ? "text-slate-700" : "text-primary opacity-40 group-hover:opacity-100")} />
                        </div>
                    </div>
                );
            })}

            {(searchTerm || filteredCoasters.length === 0) && !aiDiscoveryResults.length && (
                <div className="text-center py-8 space-y-6">
                    <div className="space-y-1">
                        <p className="text-slate-500 text-xs font-medium">Can't find it in our database?</p>
                        <p className="text-[10px] text-slate-600 uppercase font-bold tracking-widest">Try our AI or add manually</p>
                    </div>
                    <div className="grid grid-cols-1 gap-3">
                        <button 
                            onClick={handleMagicSearch} 
                            disabled={isAiSearching || !searchTerm} 
                            className={clsx(
                                "w-full py-4 rounded-2xl flex items-center justify-center gap-3 font-bold text-sm transition-all shadow-xl active:scale-95",
                                !searchTerm ? "bg-slate-800 text-slate-600 border border-slate-700" : "bg-accent text-white shadow-accent/20"
                            )}
                        >
                            {isAiSearching ? <Loader2 className="animate-spin" size={18}/> : <Sparkles size={18}/>} 
                            {isAiSearching ? 'SCOUTING...' : 'AI MAGIC DISCOVERY'}
                        </button>
                        <button onClick={() => setIsAddingManually(true)} className="w-full bg-slate-800/50 text-slate-400 py-4 rounded-2xl font-bold text-xs uppercase tracking-[0.2em] border border-slate-700 hover:text-white transition-colors">Create Manually</button>
                    </div>
                </div>
            )}
        </div>
    </div>
  );
};

export default AddCredit;

import React, { useMemo, useState, useEffect } from 'react';
import { useAppContext } from '../context/AppContext';
import { PieChart, Pie, Cell, ResponsiveContainer, Tooltip } from 'recharts';
import { Trophy, ClipboardList, Palmtree, Layers, Factory, Flag, CalendarRange, Edit2, Globe, Hash, MapPin, Navigation, ChevronRight, Zap, Star, Share2, Plus, Award, Sparkles } from 'lucide-react';
import EditCreditModal from './EditCreditModal';
import { Credit, Coaster } from '../types';
import { normalizeManufacturer } from '../constants';
import clsx from 'clsx';

type ChartMetric = 'PARK' | 'TYPE' | 'MANUFACTURER' | 'COUNTRY' | 'YEAR';

const Dashboard: React.FC = () => {
  const { credits, wishlist, coasters, activeUser, changeView, setCoasterListViewMode, setLastSearchQuery, addCredit } = useAppContext();

  const [editingCreditData, setEditingCreditData] = useState<{ credit: Credit, coaster: Coaster } | null>(null);
  const [chartMetric, setChartMetric] = useState<ChartMetric>('PARK');

  const userCredits = useMemo(() => 
    credits
      .filter(c => c.userId === activeUser.id)
      .sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime()),
  [credits, activeUser.id]);

  const userWishlist = useMemo(() => wishlist.filter(w => w.userId === activeUser.id), [wishlist, activeUser.id]);
  const uniqueCreditsCount = useMemo(() => new Set(userCredits.map(c => c.coasterId)).size, [userCredits]);
  const totalRidesCount = userCredits.length;

  const lastParkVisited = useMemo(() => {
    if (userCredits.length === 0) return null;
    const lastCredit = userCredits[0];
    const coaster = coasters.find(c => c.id === lastCredit.coasterId);
    return coaster ? coaster.park : null;
  }, [userCredits, coasters]);

  // Milestone Logic
  const milestoneLevels = [1, 10, 25, 50, 100, 250, 500];
  const nextMilestone = milestoneLevels.find(m => m > uniqueCreditsCount) || (Math.ceil((uniqueCreditsCount + 1) / 100) * 100);
  const prevMilestone = [...milestoneLevels].reverse().find(m => m <= uniqueCreditsCount) || 0;

  const progressToNext = ((uniqueCreditsCount - prevMilestone) / (nextMilestone - prevMilestone)) * 100;

  const currentLevelName = useMemo(() => {
    if (uniqueCreditsCount >= 500) return "Global Legend";
    if (uniqueCreditsCount >= 250) return "Titan of Track";
    if (uniqueCreditsCount >= 100) return "Centurion";
    if (uniqueCreditsCount >= 50) return "Pro Rider";
    if (uniqueCreditsCount >= 25) return "Expert";
    if (uniqueCreditsCount >= 10) return "Enthusiast";
    if (uniqueCreditsCount >= 1) return "Novice";
    return "Newcomer";
  }, [uniqueCreditsCount]);

  const chartData = useMemo(() => {
    const dist: Record<string, number> = {};
    const processedCoasters = new Set<string>();
    userCredits.forEach(credit => {
      if (processedCoasters.has(credit.coasterId)) return;
      processedCoasters.add(credit.coasterId);
      const coaster = coasters.find(c => c.id === credit.coasterId);
      if (coaster) {
        let key = 'Unknown';
        switch (chartMetric) {
            case 'PARK': key = coaster.park; break;
            case 'TYPE': key = coaster.type; break;
            case 'MANUFACTURER': key = normalizeManufacturer(coaster.manufacturer); break;
            case 'COUNTRY': key = coaster.country; break;
            case 'YEAR': key = new Date(credit.date).getFullYear().toString(); break;
        }
        dist[key] = (dist[key] || 0) + 1;
      }
    });
    return Object.entries(dist).map(([name, value]) => ({ name, value })).sort((a, b) => b.value - a.value).slice(0, 8);
  }, [userCredits, coasters, chartMetric]);

  const COLORS = ['#0ea5e9', '#8b5cf6', '#f43f5e', '#10b981', '#f59e0b', '#6366f1', '#ec4899', '#14b8a6'];
  const recentCredit = userCredits.length > 0 ? userCredits[0] : null;
  const recentCoaster = recentCredit ? coasters.find(c => c.id === recentCredit.coasterId) : null;

  const handleQuickLog = (e: React.MouseEvent) => {
      e.stopPropagation();
      if (recentCoaster) {
          addCredit(recentCoaster.id, new Date().toISOString().split('T')[0], 'Marathon ride!', '');
          showNotification(`Logged ${recentCoaster.name} again!`, 'success');
      }
  };

  const handleContinueMarathon = () => {
    if (lastParkVisited) {
        setLastSearchQuery(lastParkVisited);
        changeView('ADD_CREDIT');
    }
  };

  const MetricButton = ({ mode, label, icon: Icon }: { mode: ChartMetric, label: string, icon: React.ElementType }) => (
      <button
        onClick={() => setChartMetric(mode)}
        className={clsx(
            "flex items-center gap-1.5 px-3 py-1.5 rounded-lg text-[10px] font-bold uppercase tracking-wide transition-all border",
            chartMetric === mode ? "bg-primary text-white border-primary shadow-lg shadow-primary/20" : "bg-slate-900 border-slate-700 text-slate-400 hover:text-white"
        )}
      >
          <Icon size={12} />
          {label}
      </button>
  );

  return (
    <div className="space-y-6 animate-fade-in pb-10">

      {/* 1. Milestone Progress Card */}
      <div 
        onClick={() => changeView('MILESTONES')}
        className="group relative bg-slate-800/60 backdrop-blur-md border border-slate-700 p-6 rounded-[32px] overflow-hidden cursor-pointer active:scale-[0.98] transition-all shadow-2xl"
      >
          <div className="absolute top-0 right-0 w-32 h-32 bg-primary/20 blur-[60px] group-hover:bg-primary/40 transition-all rounded-full" />

          <div className="flex items-center justify-between relative z-10">
              <div className="space-y-2">
                  <div className="flex items-center gap-2">
                    <span className="bg-primary/20 text-primary px-2.5 py-1 rounded-lg text-[10px] font-black uppercase tracking-[0.2em] border border-primary/30">
                        {currentLevelName}
                    </span>
                    <Sparkles size={14} className="text-amber-400 animate-pulse" />
                  </div>
                  <h3 className="text-3xl font-black text-white italic tracking-tighter">
                    {uniqueCreditsCount} <span className="text-slate-500 text-xl font-bold">/ {nextMilestone}</span>
                  </h3>
                  <p className="text-[10px] font-bold text-slate-400 uppercase tracking-widest flex items-center gap-1">
                    Progress to Next Badge <ChevronRight size={10} className="text-primary" />
                  </p>
              </div>

              <div className="relative w-20 h-20">
                  <div className="absolute inset-0 bg-primary/10 rounded-full animate-ping opacity-20" />
                  <svg className="w-full h-full transform -rotate-90">
                      <circle cx="40" cy="40" r="34" stroke="currentColor" strokeWidth="8" fill="transparent" className="text-slate-900" />
                      <circle cx="40" cy="40" r="34" stroke="currentColor" strokeWidth="8" fill="transparent" strokeDasharray={2 * Math.PI * 34} strokeDashoffset={2 * Math.PI * 34 * (1 - progressToNext / 100)} className="text-primary transition-all duration-1000 ease-out" strokeLinecap="round" />
                  </svg>
                  <div className="absolute inset-0 flex items-center justify-center">
                      <Award size={28} className="text-primary drop-shadow-[0_0_10px_rgba(14,165,233,0.5)]" />
                  </div>
              </div>
          </div>

          <div className="mt-6 flex items-center gap-3">
              <div className="flex-1 h-2 bg-slate-900 rounded-full overflow-hidden">
                  <div className="h-full bg-gradient-to-r from-primary via-primary/80 to-accent transition-all duration-1000" style={{ width: `${progressToNext}%` }} />
              </div>
              <span className="text-[10px] font-black text-slate-500 italic">{Math.round(progressToNext)}%</span>
          </div>
      </div>

      {/* 2. Marathon Continue (Recovered Feature) */}
      {lastParkVisited && (
        <button 
            onClick={handleContinueMarathon}
            className="w-full bg-gradient-to-r from-emerald-600/20 to-teal-600/10 border border-emerald-500/30 p-4 rounded-2xl flex items-center justify-between group active:scale-[0.98] transition-all shadow-xl"
        >
            <div className="flex items-center gap-4">
                <div className="bg-emerald-500 p-2.5 rounded-xl text-white shadow-lg shadow-emerald-500/20">
                    <Zap size={22} fill="currentColor" />
                </div>
                <div className="text-left">
                    <h3 className="font-bold text-white text-base leading-tight">Park Marathon</h3>
                    <p className="text-[10px] text-emerald-500 font-black uppercase tracking-widest mt-0.5">Continue logging at {lastParkVisited}</p>
                </div>
            </div>
            <ChevronRight size={18} className="text-emerald-500/50 group-hover:text-emerald-500 transition-all" />
        </button>
      )}

      {/* 3. Main Stats Grid */}
      <div className="grid grid-cols-2 gap-4">
        <div 
            className="bg-slate-800 rounded-2xl p-5 shadow-lg border border-slate-700 relative overflow-hidden cursor-pointer active:scale-95 transition-transform group"
            onClick={() => { setCoasterListViewMode('CREDITS'); changeView('COASTER_LIST'); }}
        >
            <div className="relative z-10">
                <h2 className="text-slate-400 text-[10px] font-bold uppercase tracking-wider">Unique Credits</h2>
                <div className="text-4xl font-black text-white mt-1 tracking-tighter">{uniqueCreditsCount}</div>
                <div className="flex items-center gap-1 mt-2 text-[10px] font-bold text-primary bg-primary/10 w-fit px-2 py-1 rounded-md">
                    <Zap size={10} /> {totalRidesCount} TOTAL RIDES
                </div>
            </div>
        </div>

        <div 
            className="bg-slate-800 rounded-2xl p-5 shadow-lg border border-slate-700 relative overflow-hidden cursor-pointer active:scale-95 transition-transform group" 
            onClick={() => { setCoasterListViewMode('WISHLIST'); changeView('COASTER_LIST'); }}
        >
            <div className="relative z-10">
                 <h2 className="text-slate-400 text-[10px] font-bold uppercase tracking-wider">Bucket List</h2>
                 <div className="text-4xl font-black text-white mt-1 tracking-tighter">{userWishlist.length}</div>
                 <p className="text-amber-500 mt-1 text-[10px] font-bold flex items-center gap-1">GO TO LIST <ChevronRight size={10} /></p>
            </div>
        </div>
      </div>

      {/* 4. Statistics Panel */}
      <div className="bg-slate-800 p-5 rounded-2xl border border-slate-700 shadow-xl">
            <div className="flex justify-between items-center mb-6">
                <h3 className="text-lg font-bold text-white flex items-center gap-2">Insights</h3>
                <div className="flex gap-1 overflow-x-auto no-scrollbar max-w-[60%]">
                    <MetricButton mode="PARK" label="Park" icon={Palmtree} />
                    <MetricButton mode="TYPE" label="Type" icon={Layers} />
                    <MetricButton mode="MANUFACTURER" label="Brand" icon={Factory} />
                </div>
            </div>

            {uniqueCreditsCount > 0 ? (
                <div className="flex flex-col sm:flex-row items-center gap-6">
                    <div className="h-40 w-40 relative shrink-0">
                        <ResponsiveContainer width="100%" height="100%">
                            <PieChart>
                                <Pie data={chartData} cx="50%" cy="50%" innerRadius={45} outerRadius={65} paddingAngle={4} dataKey="value" stroke="none">
                                    {chartData.map((entry, index) => <Cell key={`cell-${index}`} fill={COLORS[index % COLORS.length]} />)}
                                </Pie>
                                <Tooltip contentStyle={{ backgroundColor: '#0f172a', border: 'none', borderRadius: '12px' }} />
                            </PieChart>
                        </ResponsiveContainer>
                    </div>
                    <div className="flex-1 grid grid-cols-1 gap-2 w-full">
                        {chartData.slice(0, 4).map((entry, index) => (
                            <div key={entry.name} className="flex items-center justify-between text-xs bg-slate-900/40 p-2.5 rounded-xl border border-slate-700/50">
                                <div className="flex items-center gap-3 truncate">
                                    <div className="w-2 h-2 rounded-full shrink-0" style={{ backgroundColor: COLORS[index % COLORS.length] }}></div>
                                    <span className="text-slate-300 truncate font-medium">{entry.name}</span>
                                </div>
                                <span className="font-bold text-white">{entry.value}</span>
                            </div>
                        ))}
                    </div>
                </div>
            ) : (
                <div className="h-40 w-full flex flex-col items-center justify-center text-slate-500 border-2 border-dashed border-slate-700 rounded-2xl bg-slate-800/50">
                    <p className="text-xs font-medium">No data to visualize yet</p>
                </div>
            )}
      </div>

      {editingCreditData && <EditCreditModal credit={editingCreditData.credit} coaster={editingCreditData.coaster} onClose={() => setEditingCreditData(null)} />}
    </div>
  );
};

export default Dashboard;

import React, { useState, useMemo } from 'react';
import { useAppContext } from '../context/AppContext';
import { Coaster, CoasterType } from '../types';
import { Search, Plus, Calendar, Sparkles, Loader2, Filter, Bookmark, BookmarkCheck, PlusCircle, ArrowLeft as BackIcon, Zap, Ruler, ArrowUp, History, Trash2, Clock, CheckCircle2, Globe, Info, X, Palmtree, ChevronRight } from 'lucide-react';
import { cleanName } from '../constants';
import clsx from 'clsx';

const normalizeText = (text: string) => cleanName(text).toLowerCase();

const AddCredit: React.FC = () => {
  const { coasters, addCredit, deleteCredit, addNewCoaster, addMultipleCoasters, searchOnlineCoaster, credits, activeUser, addToWishlist, removeFromWishlist, isInWishlist, lastSearchQuery, setLastSearchQuery, showNotification } = useAppContext();

  const searchTerm = lastSearchQuery;
  const setSearchTerm = setLastSearchQuery;
  const [selectedCoaster, setSelectedCoaster] = useState<Coaster | null>(null);
  const [isAiSearching, setIsAiSearching] = useState(false);
  const [isAddingManually, setIsAddingManually] = useState(false);
  const [aiDiscoveryResults, setAiDiscoveryResults] = useState<Partial<Coaster>[]>([]);

  const [manualCoasterData, setManualCoasterData] = useState({ name: '', park: '', country: '', manufacturer: '', type: 'Steel' as CoasterType });
  const [filterType, setFilterType] = useState<string>('All');
  const [showFilters, setShowFilters] = useState(false);
  const [hideRidden, setHideRidden] = useState(false);
  const [date, setDate] = useState<string>(new Date().toISOString().split('T')[0]);
  const [notes, setNotes] = useState('');
  const [restraints, setRestraints] = useState('');
  const [photo, setPhoto] = useState<File | undefined>(undefined);

  // Detect if we are in a "Park Marathon" (filtering by a specific park)
  const isMarathonMode = useMemo(() => {
    if (!searchTerm) return false;
    // Check if the search term exactly matches a park name in our database
    return coasters.some(c => normalizeText(c.park) === normalizeText(searchTerm));
  }, [searchTerm, coasters]);

  const filteredCoasters = useMemo(() => {
    let result = coasters;
    if (searchTerm) {
        const normalizedSearch = normalizeText(searchTerm);
        result = result.filter(c => normalizeText(c.name).includes(normalizedSearch) || normalizeText(c.park).includes(normalizedSearch));
    }
    if (filterType !== 'All') result = result.filter(c => c.type === filterType);
    if (hideRidden) result = result.filter(c => !credits.some(cr => cr.userId === activeUser.id && cr.coasterId === c.id));
    return result.sort((a, b) => a.name.localeCompare(b.name));
  }, [coasters, searchTerm, filterType, hideRidden, credits, activeUser.id]);

  const marathonStats = useMemo(() => {
      if (!isMarathonMode) return null;
      const parkCoasters = coasters.filter(c => normalizeText(c.park) === normalizeText(searchTerm));
      const riddenCount = parkCoasters.filter(c => credits.some(cr => cr.userId === activeUser.id && cr.coasterId === c.id)).length;
      return { total: parkCoasters.length, ridden: riddenCount };
  }, [isMarathonMode, searchTerm, coasters, credits, activeUser.id]);

  const handleMagicSearch = async () => {
      if (!searchTerm) return;
      setIsAiSearching(true);
      setAiDiscoveryResults([]);
      const results = await searchOnlineCoaster(searchTerm);
      setIsAiSearching(false);

      if (results && results.length > 0) {
          if (results.length === 1) {
              const res = results[0];
              if (window.confirm(`Found: ${res.name} at ${res.park}. Add to database?`)) {
                  const newC = await addNewCoaster(res as Omit<Coaster, 'id'>);
                  setSelectedCoaster(newC);
              }
          } else {
              setAiDiscoveryResults(results);
          }
      } else {
          showNotification("No coasters found.", "info");
      }
  };

  const handleQuickLogOneTap = (e: React.MouseEvent, coasterId: string) => {
    e.stopPropagation();
    addCredit(coasterId, new Date().toISOString().split('T')[0], '', '');
    showNotification("Lap logged!", "success");
  };

  const handleEnterMarathon = (e: React.MouseEvent, parkName: string) => {
      e.stopPropagation();
      setSearchTerm(parkName);
      showNotification(`Entering ${parkName} Lineup`, 'info');
  };

  const processLog = (filterByPark: boolean) => {
    if (selectedCoaster) {
        addCredit(selectedCoaster.id, date, notes, restraints, photo);
        if (filterByPark) {
            setSearchTerm(selectedCoaster.park);
        }
        setNotes(''); setRestraints(''); setPhoto(undefined);
        setSelectedCoaster(null); 
    }
  };

  if (isAddingManually) {
      return (
          <div className="animate-fade-in pb-20">
              <div className="flex items-center gap-3 mb-6">
                <button onClick={() => setIsAddingManually(false)} className="p-2 rounded-xl bg-slate-800 border border-slate-700 text-slate-400"><BackIcon size={20}/></button>
                <h2 className="text-xl font-bold">Add Coaster Manually</h2>
              </div>
              <form onSubmit={async (e) => {
                  e.preventDefault();
                  const newC = await addNewCoaster({ ...manualCoasterData, isCustom: true });
                  setIsAddingManually(false);
                  setSelectedCoaster(newC);
              }} className="bg-slate-800 p-6 rounded-2xl border border-slate-700 space-y-4">
                  <input required placeholder="Coaster Name" value={manualCoasterData.name} onChange={e => setManualCoasterData({...manualCoasterData, name: e.target.value})} className="w-full bg-slate-900 border border-slate-600 rounded-xl p-3 text-white" />
                  <input required placeholder="Park Name" value={manualCoasterData.park} onChange={e => setManualCoasterData({...manualCoasterData, park: e.target.value})} className="w-full bg-slate-900 border border-slate-600 rounded-xl p-3 text-white" />
                  <div className="pt-4"><button type="submit" className="w-full bg-primary py-3.5 rounded-xl font-bold">Save & Log Ride</button></div>
              </form>
          </div>
      );
  }

  if (selectedCoaster) {
      return (
          <div className="animate-fade-in pb-24 space-y-4">
                <div className="sticky top-0 -mx-4 -mt-4 p-4 z-20 bg-slate-900/95 backdrop-blur-md border-b border-slate-700/50 flex gap-2">
                    <button onClick={() => setSelectedCoaster(null)} className="p-3 rounded-xl bg-slate-800 border border-slate-700 text-slate-400"><BackIcon size={20}/></button>
                    <button onClick={() => processLog(true)} className="flex-1 bg-emerald-500/10 text-emerald-400 font-bold py-3 rounded-xl border border-emerald-500/30 flex items-center justify-center gap-2">
                        <Palmtree size={18} /> Log & View Park
                    </button>
                </div>

                {selectedCoaster.imageUrl && (
                    <div className="w-full h-48 rounded-2xl overflow-hidden shadow-lg border border-slate-700 relative">
                        <img src={selectedCoaster.imageUrl} alt={selectedCoaster.name} className="w-full h-full object-cover" />
                        <div className="absolute inset-0 bg-gradient-to-t from-slate-950 via-transparent to-transparent" />
                        <div className="absolute bottom-4 left-4">
                            <h2 className="text-3xl font-black text-white leading-tight italic drop-shadow-md">{selectedCoaster.name}</h2>
                            <div className="text-slate-300 text-sm font-bold flex items-center gap-1 uppercase tracking-wider"><Globe size={14} className="text-primary"/> {selectedCoaster.park}</div>
                        </div>
                    </div>
                )}

                <div className="bg-slate-800 p-5 rounded-3xl border border-slate-700 space-y-4 shadow-xl">
                    <div className="flex items-center justify-between mb-2">
                        <h3 className="font-bold text-white flex items-center gap-2 text-sm uppercase tracking-widest text-slate-400"><Clock size={16} className="text-primary"/> Detailed Log</h3>
                    </div>
                    <div>
                        <label className="block text-[10px] font-bold text-slate-500 uppercase tracking-widest mb-1.5">Date</label>
                        <input type="date" required value={date} onChange={e => setDate(e.target.value)} className="w-full bg-slate-900 border border-slate-600 rounded-xl p-3 text-white text-sm" />
                    </div>
                    <div>
                        <label className="block text-[10px] font-bold text-slate-500 uppercase tracking-widest mb-1.5">Experience (Optional)</label>
                        <textarea value={notes} onChange={e => setNotes(e.target.value)} placeholder="How was the ride? Seat location?" className="w-full bg-slate-900 border border-slate-600 rounded-xl p-3 text-white text-sm h-20 outline-none" />
                    </div>
                    <button onClick={() => processLog(false)} className="w-full bg-primary font-bold py-4 rounded-2xl shadow-xl shadow-primary/30 flex items-center justify-center gap-2 active:scale-95 transition-all"><Plus size={20}/> LOG CREDIT</button>
                </div>
          </div>
      );
  }

  return (
    <div className="h-full flex flex-col space-y-5 animate-fade-in">

        {/* Marathon Mode Header (RECOVERED & ENHANCED) */}
        {isMarathonMode && marathonStats ? (
            <div className="bg-gradient-to-r from-emerald-500 to-emerald-700 rounded-3xl p-5 flex items-center justify-between shadow-xl shadow-emerald-900/40 border border-white/20 animate-scale-in relative overflow-hidden group">
                <div className="absolute top-0 right-0 p-2 opacity-10 group-hover:scale-125 transition-transform">
                    <Palmtree size={100} />
                </div>
                <div className="flex items-center gap-4 relative z-10">
                    <div className="bg-white p-3 rounded-2xl text-emerald-600 shadow-lg rotate-3">
                        <Palmtree size={24} fill="currentColor" />
                    </div>
                    <div>
                        <h3 className="text-base font-black text-white italic leading-tight uppercase tracking-tight">PARK LINEUP</h3>
                        <p className="text-xs text-emerald-100 font-bold uppercase tracking-widest opacity-80">{searchTerm}</p>
                    </div>
                </div>
                <div className="flex items-center gap-4 relative z-10">
                    <div className="text-right">
                        <div className="text-xl font-black text-white italic">{marathonStats.ridden} / {marathonStats.total}</div>
                        <div className="text-[8px] text-emerald-100 font-black uppercase tracking-[0.2em]">RIDDEN</div>
                    </div>
                    <button onClick={() => setSearchTerm('')} className="bg-black/20 hover:bg-black/40 p-2 rounded-xl text-white transition-colors border border-white/10">
                        <X size={20} />
                    </button>
                </div>
            </div>
        ) : (
            <div className="space-y-1">
                <h2 className="text-2xl font-black text-white italic tracking-tight">ADD <span className="text-primary">CREDIT</span></h2>
                <p className="text-[10px] font-bold text-slate-500 uppercase tracking-[0.2em]">Search our database or use AI</p>
            </div>
        )}

        <div className="space-y-3">
          <div className="flex gap-2">
              <div className="relative flex-1">
                  <Search className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-500" size={18} />
                  <input 
                      type="text" 
                      placeholder="Search coaster or park name..." 
                      value={searchTerm} 
                      onChange={e => setSearchTerm(e.target.value)} 
                      className="w-full bg-slate-900 border border-slate-700 rounded-2xl pl-12 py-4 text-white shadow-lg focus:border-primary focus:ring-1 focus:ring-primary outline-none text-sm transition-all" 
                  />
              </div>
              <button onClick={() => setShowFilters(!showFilters)} className={clsx("p-4 rounded-2xl border transition-all active:scale-95", showFilters ? "bg-primary border-primary text-white" : "bg-slate-800 border-slate-700 text-slate-500")}><Filter size={20}/></button>
          </div>
        </div>

        <div className="flex-1 overflow-y-auto space-y-3 no-scrollbar pb-20">
            {filteredCoasters.map(c => {
                const isRidden = credits.some(cr => cr.userId === activeUser.id && cr.coasterId === c.id);
                return (
                    <div key={c.id} onClick={() => setSelectedCoaster(c)} className={clsx("bg-slate-800/40 rounded-2xl border flex items-stretch h-24 overflow-hidden cursor-pointer hover:bg-slate-800 transition-all active:scale-[0.99] group", isRidden ? "border-emerald-500/30 bg-emerald-500/5" : "border-slate-700/50")}>
                        <div className="w-24 shrink-0 bg-slate-900 border-r border-slate-700/50 overflow-hidden relative">
                            {c.imageUrl && <img src={c.imageUrl} className={clsx("w-full h-full object-cover transition-opacity", isRidden ? "opacity-30" : "opacity-80 group-hover:opacity-100")} />}
                            <div className="absolute inset-0 bg-gradient-to-t from-slate-900/60 to-transparent" />
                            {isRidden && <div className="absolute inset-0 flex items-center justify-center"><CheckCircle2 size={24} className="text-emerald-500 drop-shadow-md" /></div>}
                        </div>
                        <div className="flex-1 px-4 py-2 flex flex-col justify-center min-w-0">
                            <h3 className={clsx("font-bold text-base truncate leading-tight italic", isRidden ? "text-emerald-400" : "text-slate-100")}>{c.name}</h3>
                            <div className="text-[10px] text-slate-500 truncate font-bold uppercase tracking-wider mt-0.5">{c.park}</div>

                            {!isMarathonMode && (
                                <button 
                                    onClick={(e) => handleEnterMarathon(e, c.park)}
                                    className="mt-2 flex items-center gap-1.5 text-[8px] font-black text-emerald-500 uppercase tracking-widest bg-emerald-500/10 w-fit px-2 py-1 rounded-md border border-emerald-500/20 hover:bg-emerald-500 hover:text-white transition-all"
                                >
                                    <Palmtree size={10} /> View Park Lineup
                                </button>
                            )}
                        </div>

                        <div className="flex items-center px-4">
                            {isRidden && isMarathonMode ? (
                                <button onClick={(e) => handleQuickLogOneTap(e, c.id)} className="bg-emerald-500 p-2.5 rounded-xl text-white shadow-lg active:scale-90 transition-all">
                                    <Plus size={18} />
                                </button>
                            ) : (
                                <div className="p-3 text-slate-700 group-hover:text-primary transition-colors">
                                    <ChevronRight size={20} />
                                </div>
                            )}
                        </div>
                    </div>
                );
            })}

            {(searchTerm || filteredCoasters.length === 0) && (
                <div className="text-center py-8 space-y-6">
                    <button 
                        onClick={handleMagicSearch} 
                        disabled={isAiSearching || !searchTerm} 
                        className={clsx(
                            "w-full py-4 rounded-2xl flex items-center justify-center gap-3 font-bold text-sm transition-all shadow-xl active:scale-95",
                            !searchTerm ? "bg-slate-800 text-slate-600 border border-slate-700" : "bg-accent text-white shadow-accent/20"
                        )}
                    >
                        {isAiSearching ? <Loader2 className="animate-spin" size={18}/> : <Sparkles size={18}/>} 
                        {isAiSearching ? 'SCOUTING...' : 'AI MAGIC DISCOVERY'}
                    </button>
                    <button onClick={() => setIsAddingManually(true)} className="w-full bg-slate-800/50 text-slate-400 py-4 rounded-2xl font-bold text-xs uppercase tracking-[0.2em] border border-slate-700">Add Custom Coaster</button>
                </div>
            )}
        </div>
    </div>
  );
};

export default AddCredit;

import React, { useMemo, useState, useEffect } from 'react';
import { useAppContext } from '../context/AppContext';
import { PieChart, Pie, Cell, ResponsiveContainer, Tooltip } from 'recharts';
import { Trophy, ClipboardList, Palmtree, Layers, Factory, Flag, CalendarRange, Edit2, Globe, Hash, MapPin, Navigation, ChevronRight, Zap, Star, Share2, Plus, Award, Sparkles } from 'lucide-react';
import EditCreditModal from './EditCreditModal';
import { Credit, Coaster } from '../types';
import { normalizeManufacturer } from '../constants';
import clsx from 'clsx';

type ChartMetric = 'PARK' | 'TYPE' | 'MANUFACTURER' | 'COUNTRY' | 'YEAR';

const Dashboard: React.FC = () => {
  const { credits, wishlist, coasters, activeUser, changeView, setCoasterListViewMode, setLastSearchQuery, addCredit, showNotification } = useAppContext();

  const [editingCreditData, setEditingCreditData] = useState<{ credit: Credit, coaster: Coaster } | null>(null);
  const [chartMetric, setChartMetric] = useState<ChartMetric>('PARK');

  const userCredits = useMemo(() => 
    credits
      .filter(c => c.userId === activeUser.id)
      .sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime()),
  [credits, activeUser.id]);

  const userWishlist = useMemo(() => wishlist.filter(w => w.userId === activeUser.id), [wishlist, activeUser.id]);
  const uniqueCreditsCount = useMemo(() => new Set(userCredits.map(c => c.coasterId)).size, [userCredits]);
  const totalRidesCount = userCredits.length;

  const lastParkVisited = useMemo(() => {
    if (userCredits.length === 0) return null;
    const lastCredit = userCredits[0];
    const coaster = coasters.find(c => c.id === lastCredit.coasterId);
    return coaster ? coaster.park : null;
  }, [userCredits, coasters]);

  // Milestone Logic
  const milestoneLevels = [1, 10, 25, 50, 100, 250, 500];
  const nextMilestone = milestoneLevels.find(m => m > uniqueCreditsCount) || (Math.ceil((uniqueCreditsCount + 1) / 100) * 100);
  const prevMilestone = [...milestoneLevels].reverse().find(m => m <= uniqueCreditsCount) || 0;

  const progressToNext = ((uniqueCreditsCount - prevMilestone) / (nextMilestone - prevMilestone)) * 100;

  const currentLevelName = useMemo(() => {
    if (uniqueCreditsCount >= 500) return "Global Legend";
    if (uniqueCreditsCount >= 250) return "Titan of Track";
    if (uniqueCreditsCount >= 100) return "Centurion";
    if (uniqueCreditsCount >= 50) return "Pro Rider";
    if (uniqueCreditsCount >= 25) return "Expert";
    if (uniqueCreditsCount >= 10) return "Enthusiast";
    if (uniqueCreditsCount >= 1) return "Novice";
    return "Newcomer";
  }, [uniqueCreditsCount]);

  const chartData = useMemo(() => {
    const dist: Record<string, number> = {};
    const processedCoasters = new Set<string>();
    userCredits.forEach(credit => {
      if (processedCoasters.has(credit.coasterId)) return;
      processedCoasters.add(credit.coasterId);
      const coaster = coasters.find(c => c.id === credit.coasterId);
      if (coaster) {
        let key = 'Unknown';
        switch (chartMetric) {
            case 'PARK': key = coaster.park; break;
            case 'TYPE': key = coaster.type; break;
            case 'MANUFACTURER': key = normalizeManufacturer(coaster.manufacturer); break;
            case 'COUNTRY': key = coaster.country; break;
            case 'YEAR': key = new Date(credit.date).getFullYear().toString(); break;
        }
        dist[key] = (dist[key] || 0) + 1;
      }
    });
    return Object.entries(dist).map(([name, value]) => ({ name, value })).sort((a, b) => b.value - a.value).slice(0, 8);
  }, [userCredits, coasters, chartMetric]);

  const COLORS = ['#0ea5e9', '#8b5cf6', '#f43f5e', '#10b981', '#f59e0b', '#6366f1', '#ec4899', '#14b8a6'];
  const recentCredit = userCredits.length > 0 ? userCredits[0] : null;
  const recentCoaster = recentCredit ? coasters.find(c => c.id === recentCredit.coasterId) : null;

  const handleContinueMarathon = () => {
    if (lastParkVisited) {
        setLastSearchQuery(lastParkVisited);
        changeView('ADD_CREDIT');
    }
  };

  const MetricButton = ({ mode, label, icon: Icon }: { mode: ChartMetric, label: string, icon: React.ElementType }) => (
      <button
        onClick={() => setChartMetric(mode)}
        className={clsx(
            "flex items-center gap-1.5 px-3 py-1.5 rounded-lg text-[10px] font-bold uppercase tracking-wide transition-all border",
            chartMetric === mode ? "bg-primary text-white border-primary shadow-lg shadow-primary/20" : "bg-slate-900 border-slate-700 text-slate-400 hover:text-white"
        )}
      >
          <Icon size={12} />
          {label}
      </button>
  );

  return (
    <div className="space-y-6 animate-fade-in pb-10">

      {/* 1. Milestone Progress Card */}
      <div 
        onClick={() => changeView('MILESTONES')}
        className="group relative bg-slate-800/60 backdrop-blur-md border border-slate-700 p-6 rounded-[32px] overflow-hidden cursor-pointer active:scale-[0.98] transition-all shadow-2xl"
      >
          <div className="absolute top-0 right-0 w-32 h-32 bg-primary/20 blur-[60px] group-hover:bg-primary/40 transition-all rounded-full" />

          <div className="flex items-center justify-between relative z-10">
              <div className="space-y-2">
                  <div className="flex items-center gap-2">
                    <span className="bg-primary/20 text-primary px-2.5 py-1 rounded-lg text-[10px] font-black uppercase tracking-[0.2em] border border-primary/30">
                        {currentLevelName}
                    </span>
                    <Sparkles size={14} className="text-amber-400 animate-pulse" />
                  </div>
                  <h3 className="text-3xl font-black text-white italic tracking-tighter">
                    {uniqueCreditsCount} <span className="text-slate-500 text-xl font-bold">/ {nextMilestone}</span>
                  </h3>
                  <p className="text-[10px] font-bold text-slate-400 uppercase tracking-widest flex items-center gap-1">
                    Progress to Next Badge <ChevronRight size={10} className="text-primary" />
                  </p>
              </div>

              <div className="relative w-20 h-20">
                  <div className="absolute inset-0 bg-primary/10 rounded-full animate-ping opacity-20" />
                  <svg className="w-full h-full transform -rotate-90">
                      <circle cx="40" cy="40" r="34" stroke="currentColor" strokeWidth="8" fill="transparent" className="text-slate-900" />
                      <circle cx="40" cy="40" r="34" stroke="currentColor" strokeWidth="8" fill="transparent" strokeDasharray={2 * Math.PI * 34} strokeDashoffset={2 * Math.PI * 34 * (1 - progressToNext / 100)} className="text-primary transition-all duration-1000 ease-out" strokeLinecap="round" />
                  </svg>
                  <div className="absolute inset-0 flex items-center justify-center">
                      <Award size={28} className="text-primary drop-shadow-[0_0_10px_rgba(14,165,233,0.5)]" />
                  </div>
              </div>
          </div>

          <div className="mt-6 flex items-center gap-3">
              <div className="flex-1 h-2 bg-slate-900 rounded-full overflow-hidden">
                  <div className="h-full bg-gradient-to-r from-primary via-primary/80 to-accent transition-all duration-1000" style={{ width: `${progressToNext}%` }} />
              </div>
              <span className="text-[10px] font-black text-slate-500 italic">{Math.round(progressToNext)}%</span>
          </div>
      </div>

      {/* 2. Marathon Continue (Recovered Feature with correct Green Palm Tree icon) */}
      {lastParkVisited && (
        <button 
            onClick={handleContinueMarathon}
            className="w-full bg-gradient-to-r from-emerald-600/20 to-teal-600/10 border border-emerald-500/30 p-4 rounded-3xl flex items-center justify-between group active:scale-[0.98] transition-all shadow-xl"
        >
            <div className="flex items-center gap-4">
                <div className="bg-emerald-500 p-2.5 rounded-2xl text-white shadow-lg shadow-emerald-500/30 rotate-3 group-hover:rotate-0 transition-transform">
                    <Palmtree size={22} fill="currentColor" />
                </div>
                <div className="text-left">
                    <h3 className="font-bold text-white text-base leading-tight">Park Lineup</h3>
                    <p className="text-[10px] text-emerald-500 font-black uppercase tracking-widest mt-0.5">Quick-log at {lastParkVisited}</p>
                </div>
            </div>
            <ChevronRight size={18} className="text-emerald-500/50 group-hover:text-emerald-500 group-hover:translate-x-1 transition-all" />
        </button>
      )}

      {/* 3. Main Stats Grid */}
      <div className="grid grid-cols-2 gap-4">
        <div 
            className="bg-slate-800 rounded-2xl p-5 shadow-lg border border-slate-700 relative overflow-hidden cursor-pointer active:scale-95 transition-transform group"
            onClick={() => { setCoasterListViewMode('CREDITS'); changeView('COASTER_LIST'); }}
        >
            <div className="relative z-10">
                <h2 className="text-slate-400 text-[10px] font-bold uppercase tracking-wider">Unique Credits</h2>
                <div className="text-4xl font-black text-white mt-1 tracking-tighter">{uniqueCreditsCount}</div>
                <div className="flex items-center gap-1 mt-2 text-[10px] font-bold text-primary bg-primary/10 w-fit px-2 py-1 rounded-md">
                    <Zap size={10} /> {totalRidesCount} TOTAL
                </div>
            </div>
        </div>

        <div 
            className="bg-slate-800 rounded-2xl p-5 shadow-lg border border-slate-700 relative overflow-hidden cursor-pointer active:scale-95 transition-transform group" 
            onClick={() => { setCoasterListViewMode('WISHLIST'); changeView('COASTER_LIST'); }}
        >
            <div className="relative z-10">
                 <h2 className="text-slate-400 text-[10px] font-bold uppercase tracking-wider">Bucket List</h2>
                 <div className="text-4xl font-black text-white mt-1 tracking-tighter">{userWishlist.length}</div>
                 <p className="text-amber-500 mt-1 text-[10px] font-bold flex items-center gap-1">GO TO LIST <ChevronRight size={10} /></p>
            </div>
        </div>
      </div>

      {/* 4. Statistics Panel */}
      <div className="bg-slate-800 p-5 rounded-3xl border border-slate-700 shadow-xl">
            <div className="flex justify-between items-center mb-6">
                <h3 className="text-lg font-bold text-white flex items-center gap-2">Insights</h3>
                <div className="flex gap-1 overflow-x-auto no-scrollbar max-w-[60%]">
                    <MetricButton mode="PARK" label="Park" icon={Palmtree} />
                    <MetricButton mode="TYPE" label="Type" icon={Layers} />
                    <MetricButton mode="MANUFACTURER" label="Brand" icon={Factory} />
                </div>
            </div>

            {uniqueCreditsCount > 0 ? (
                <div className="flex flex-col sm:flex-row items-center gap-6">
                    <div className="h-40 w-40 relative shrink-0">
                        <ResponsiveContainer width="100%" height="100%">
                            <PieChart>
                                <Pie data={chartData} cx="50%" cy="50%" innerRadius={45} outerRadius={65} paddingAngle={4} dataKey="value" stroke="none">
                                    {chartData.map((entry, index) => <Cell key={`cell-${index}`} fill={COLORS[index % COLORS.length]} />)}
                                </Pie>
                                <Tooltip contentStyle={{ backgroundColor: '#0f172a', border: 'none', borderRadius: '12px' }} />
                            </PieChart>
                        </ResponsiveContainer>
                    </div>
                    <div className="flex-1 grid grid-cols-1 gap-2 w-full">
                        {chartData.slice(0, 4).map((entry, index) => (
                            <div key={entry.name} className="flex items-center justify-between text-xs bg-slate-900/40 p-2.5 rounded-xl border border-slate-700/50">
                                <div className="flex items-center gap-3 truncate">
                                    <div className="w-2 h-2 rounded-full shrink-0" style={{ backgroundColor: COLORS[index % COLORS.length] }}></div>
                                    <span className="text-slate-300 truncate font-medium">{entry.name}</span>
                                </div>
                                <span className="font-bold text-white">{entry.value}</span>
                            </div>
                        ))}
                    </div>
                </div>
            ) : (
                <div className="h-40 w-full flex flex-col items-center justify-center text-slate-500 border-2 border-dashed border-slate-700 rounded-2xl bg-slate-800/50">
                    <p className="text-xs font-medium">No data to visualize yet</p>
                </div>
            )}
      </div>

      {editingCreditData && <EditCreditModal credit={editingCreditData.credit} coaster={editingCreditData.coaster} onClose={() => setEditingCreditData(null)} />}
    </div>
  );
};

export default Dashboard;
